1	package com.reclaim.portal.common.config;
2	
3	import com.reclaim.portal.auth.filter.JwtAuthenticationFilter;
4	import jakarta.servlet.http.HttpServletResponse;
5	import org.springframework.context.annotation.Bean;
6	import org.springframework.context.annotation.Configuration;
7	import org.springframework.security.authentication.AuthenticationManager;
8	import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
9	import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
10	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
11	import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
12	import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
13	import org.springframework.security.config.http.SessionCreationPolicy;
14	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
15	import org.springframework.security.crypto.password.PasswordEncoder;
16	import org.springframework.security.web.SecurityFilterChain;
17	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
18	
19	@Configuration
20	@EnableWebSecurity
21	@EnableMethodSecurity
22	public class SecurityConfig {
23	
24	    private final JwtAuthenticationFilter jwtAuthenticationFilter;
25	
26	    public SecurityConfig(JwtAuthenticationFilter jwtAuthenticationFilter) {
27	        this.jwtAuthenticationFilter = jwtAuthenticationFilter;
28	    }
29	
30	    @Bean
31	    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
32	        // Security model: all API endpoints use stateless JWT Bearer token authentication.
33	        // The HttpOnly refresh cookie is scoped to /api/auth only (path=/api/auth) and is set
34	        // with SameSite=Strict, which prevents cross-origin cookie attachment — the primary CSRF
35	        // vector for cookie-based tokens. Because the app is fully stateless (no server-side
36	        // session), standard CSRF mitigations that rely on session state do not apply. CSRF is
37	        // therefore disabled globally for all endpoints; the following defences are in place:
38	        //   1. SameSite=Strict cookie attribute on the refresh cookie — primary mitigation.
39	        //   2. Origin header validation in AuthApiController.validateOrigin() — called by the
40	        //      /api/auth/refresh and /api/auth/logout endpoints to reject requests whose Origin
41	        //      header does not match the server's own origin. This provides defence-in-depth
42	        //      for older browsers that may not enforce SameSite=Strict.
43	        //   3. Bearer-token pattern on all other API calls — an attacker cannot read the
44	        //      access token from a different origin, so forged requests fail authentication.
45	        http
46	            .csrf(AbstractHttpConfigurer::disable)
47	            .sessionManagement(session ->
48	                session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
49	            .exceptionHandling(ex -> ex
50	                .authenticationEntryPoint((request, response, authException) -> {
51	                    response.setContentType("application/json");
52	                    response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
53	                    response.getWriter().write("{\"status\":401,\"error\":\"Unauthorized\",\"message\":\"Authentication required\"}");
54	                })
55	            )
56	            .authorizeHttpRequests(auth -> auth
57	                .requestMatchers(
58	                    "/api/auth/**",
59	                    "/login",
60	                    "/css/**",
61	                    "/js/**",
62	                    "/images/**"
63	                ).permitAll()
64	                .requestMatchers("/api/admin/**", "/admin/**").hasRole("ADMIN")
65	                .requestMatchers("/api/reviewer/**", "/reviewer/**")
66	                    .hasAnyRole("REVIEWER", "ADMIN")
67	                .anyRequest().authenticated()
68	            )
69	            .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class);
70	
71	        return http.build();
72	    }
73	
74	    @Bean
75	    public PasswordEncoder passwordEncoder() {
76	        return new BCryptPasswordEncoder();
77	    }
78	
79	    @Bean
80	    public AuthenticationManager authenticationManager(AuthenticationConfiguration config)
81	            throws Exception {
82	        return config.getAuthenticationManager();
83	    }
84	}
