1	package com.reclaim.portal.auth.service;
2	
3	import com.reclaim.portal.auth.entity.User;
4	import com.reclaim.portal.common.config.ReclaimProperties;
5	import io.jsonwebtoken.Jwts;
6	import io.jsonwebtoken.security.Keys;
7	import org.springframework.stereotype.Service;
8	
9	import javax.crypto.SecretKey;
10	import java.nio.charset.StandardCharsets;
11	import java.time.Instant;
12	import java.time.temporal.ChronoUnit;
13	import java.util.Date;
14	import java.util.List;
15	import java.util.UUID;
16	import java.util.stream.Collectors;
17	
18	@Service
19	public class JwtService {
20	
21	    private final ReclaimProperties reclaimProperties;
22	
23	    public JwtService(ReclaimProperties reclaimProperties) {
24	        this.reclaimProperties = reclaimProperties;
25	    }
26	
27	    public String generateAccessToken(User user) {
28	        ReclaimProperties.Security security = reclaimProperties.getSecurity();
29	        SecretKey key = Keys.hmacShaKeyFor(security.getJwtSecret().getBytes(StandardCharsets.UTF_8));
30	
31	        List<String> roleNames = user.getRoles().stream()
32	            .map(role -> role.getName())
33	            .collect(Collectors.toList());
34	
35	        Instant now = Instant.now();
36	        Instant expiry = now.plus(security.getAccessTokenMinutes(), ChronoUnit.MINUTES);
37	
38	        return Jwts.builder()
39	            .subject(user.getUsername())
40	            .claim("roles", roleNames)
41	            .issuedAt(Date.from(now))
42	            .expiration(Date.from(expiry))
43	            .id(UUID.randomUUID().toString())
44	            .signWith(key)
45	            .compact();
46	    }
47	
48	    public String generateRefreshToken(User user) {
49	        ReclaimProperties.Security security = reclaimProperties.getSecurity();
50	        SecretKey key = Keys.hmacShaKeyFor(security.getRefreshSecret().getBytes(StandardCharsets.UTF_8));
51	
52	        Instant now = Instant.now();
53	        Instant expiry = now.plus(security.getRefreshTokenDays(), ChronoUnit.DAYS);
54	
55	        return Jwts.builder()
56	            .subject(user.getUsername())
57	            .issuedAt(Date.from(now))
58	            .expiration(Date.from(expiry))
59	            .id(UUID.randomUUID().toString())
60	            .signWith(key)
61	            .compact();
62	    }
63	
64	    public String extractUsername(String token) {
65	        SecretKey key = Keys.hmacShaKeyFor(
66	            reclaimProperties.getSecurity().getJwtSecret().getBytes(StandardCharsets.UTF_8));
67	        return Jwts.parser()
68	            .verifyWith(key)
69	            .build()
70	            .parseSignedClaims(token)
71	            .getPayload()
72	            .getSubject();
73	    }
74	
75	    public String extractUsernameFromRefreshToken(String token) {
76	        SecretKey key = Keys.hmacShaKeyFor(
77	            reclaimProperties.getSecurity().getRefreshSecret().getBytes(StandardCharsets.UTF_8));
78	        return Jwts.parser()
79	            .verifyWith(key)
80	            .build()
81	            .parseSignedClaims(token)
82	            .getPayload()
83	            .getSubject();
84	    }
85	
86	    public boolean isTokenValid(String token) {
87	        try {
88	            SecretKey key = Keys.hmacShaKeyFor(
89	                reclaimProperties.getSecurity().getJwtSecret().getBytes(StandardCharsets.UTF_8));
90	            Jwts.parser()
91	                .verifyWith(key)
92	                .build()
93	                .parseSignedClaims(token);
94	            return true;
95	        } catch (Exception e) {
96	            return false;
97	        }
98	    }
99	
100	    public boolean isRefreshTokenValid(String token) {
101	        try {
102	            SecretKey key = Keys.hmacShaKeyFor(
103	                reclaimProperties.getSecurity().getRefreshSecret().getBytes(StandardCharsets.UTF_8));
104	            Jwts.parser()
105	                .verifyWith(key)
106	                .build()
107	                .parseSignedClaims(token);
108	            return true;
109	        } catch (Exception e) {
110	            return false;
111	        }
112	    }
113	}
