1	package com.reclaim.portal.auth.service;
2	
3	import com.reclaim.portal.auth.dto.AuthResponse;
4	import com.reclaim.portal.auth.entity.LoginAttempt;
5	import com.reclaim.portal.auth.entity.RefreshToken;
6	import com.reclaim.portal.auth.entity.User;
7	import com.reclaim.portal.auth.repository.LoginAttemptRepository;
8	import com.reclaim.portal.auth.repository.RefreshTokenRepository;
9	import com.reclaim.portal.auth.repository.UserRepository;
10	import com.reclaim.portal.common.config.ReclaimProperties;
11	import com.reclaim.portal.common.exception.BusinessRuleException;
12	import com.reclaim.portal.common.exception.EntityNotFoundException;
13	import org.springframework.security.crypto.password.PasswordEncoder;
14	import org.springframework.stereotype.Service;
15	import org.springframework.transaction.annotation.Transactional;
16	
17	import java.nio.charset.StandardCharsets;
18	import java.security.MessageDigest;
19	import java.security.NoSuchAlgorithmException;
20	import java.time.LocalDateTime;
21	import java.util.HexFormat;
22	
23	@Service
24	@Transactional
25	public class AuthService {
26	
27	    private final UserRepository userRepository;
28	    private final RefreshTokenRepository refreshTokenRepository;
29	    private final LoginAttemptRepository loginAttemptRepository;
30	    private final PasswordEncoder passwordEncoder;
31	    private final JwtService jwtService;
32	    private final ReclaimProperties reclaimProperties;
33	
34	    public AuthService(UserRepository userRepository,
35	                       RefreshTokenRepository refreshTokenRepository,
36	                       LoginAttemptRepository loginAttemptRepository,
37	                       PasswordEncoder passwordEncoder,
38	                       JwtService jwtService,
39	                       ReclaimProperties reclaimProperties) {
40	        this.userRepository = userRepository;
41	        this.refreshTokenRepository = refreshTokenRepository;
42	        this.loginAttemptRepository = loginAttemptRepository;
43	        this.passwordEncoder = passwordEncoder;
44	        this.jwtService = jwtService;
45	        this.reclaimProperties = reclaimProperties;
46	    }
47	
48	    public AuthResponse login(String username, String password, String ipAddress) {
49	        ReclaimProperties.Security security = reclaimProperties.getSecurity();
50	        LocalDateTime now = LocalDateTime.now();
51	
52	        User user = userRepository.findByUsername(username)
53	            .orElse(null);
54	
55	        // Check lock state before verifying credentials
56	        if (user != null && user.isLocked() && user.getLockedUntil() != null
57	                && user.getLockedUntil().isAfter(now)) {
58	            recordFailedAttempt(username, ipAddress, "Account is locked");
59	            throw new BusinessRuleException("Account is locked");
60	        }
61	
62	        if (user == null || !passwordEncoder.matches(password, user.getPasswordHash())) {
63	            if (user != null) {
64	                int attempts = user.getFailedAttempts() + 1;
65	                user.setFailedAttempts(attempts);
66	                if (attempts >= security.getMaxFailedAttempts()) {
67	                    user.setLocked(true);
68	                    user.setLockedUntil(now.plusMinutes(security.getLockoutMinutes()));
69	                }
70	                user.setUpdatedAt(now);
71	                userRepository.save(user);
72	            }
73	            recordFailedAttempt(username, ipAddress, "Invalid credentials");
74	            throw new BusinessRuleException("Invalid username or password");
75	        }
76	
77	        // Successful authentication
78	        user.setFailedAttempts(0);
79	        user.setLocked(false);
80	        user.setLockedUntil(null);
81	        user.setUpdatedAt(now);
82	        userRepository.save(user);
83	
84	        LoginAttempt successAttempt = new LoginAttempt();
85	        successAttempt.setUsername(username);
86	        successAttempt.setIpAddress(ipAddress);
87	        successAttempt.setSuccess(true);
88	        successAttempt.setAttemptedAt(now);
89	        loginAttemptRepository.save(successAttempt);
90	
91	        String accessToken = jwtService.generateAccessToken(user);
92	        String refreshTokenStr = jwtService.generateRefreshToken(user);
93	        String tokenHash = hashToken(refreshTokenStr);
94	
95	        RefreshToken refreshToken = new RefreshToken();
96	        refreshToken.setUserId(user.getId());
97	        refreshToken.setTokenHash(tokenHash);
98	        refreshToken.setExpiresAt(now.plusDays(security.getRefreshTokenDays()));
99	        refreshToken.setRevoked(false);
100	        refreshToken.setCreatedAt(now);
101	        refreshTokenRepository.save(refreshToken);
102	
103	        return new AuthResponse(accessToken, refreshTokenStr, user.isForcePasswordReset());
104	    }
105	
106	    public AuthResponse refresh(String refreshTokenStr) {
107	        if (!jwtService.isRefreshTokenValid(refreshTokenStr)) {
108	            throw new BusinessRuleException("Invalid refresh token");
109	        }
110	
111	        String tokenHash = hashToken(refreshTokenStr);
112	        RefreshToken storedToken = refreshTokenRepository.findByTokenHash(tokenHash)
113	            .orElseThrow(() -> new BusinessRuleException("Refresh token not found"));
114	
115	        if (storedToken.isRevoked()) {
116	            throw new BusinessRuleException("Refresh token has been revoked");
117	        }
118	
119	        if (storedToken.getExpiresAt().isBefore(LocalDateTime.now())) {
120	            throw new BusinessRuleException("Refresh token has expired");
121	        }
122	
123	        storedToken.setRevoked(true);
124	        refreshTokenRepository.save(storedToken);
125	
126	        String username = jwtService.extractUsernameFromRefreshToken(refreshTokenStr);
127	        User user = userRepository.findByUsername(username)
128	            .orElseThrow(() -> new EntityNotFoundException("User not found: " + username));
129	
130	        ReclaimProperties.Security security = reclaimProperties.getSecurity();
131	        LocalDateTime now = LocalDateTime.now();
132	
133	        String newAccessToken = jwtService.generateAccessToken(user);
134	        String newRefreshTokenStr = jwtService.generateRefreshToken(user);
135	        String newTokenHash = hashToken(newRefreshTokenStr);
136	
137	        RefreshToken newRefreshToken = new RefreshToken();
138	        newRefreshToken.setUserId(user.getId());
139	        newRefreshToken.setTokenHash(newTokenHash);
140	        newRefreshToken.setExpiresAt(now.plusDays(security.getRefreshTokenDays()));
141	        newRefreshToken.setRevoked(false);
142	        newRefreshToken.setCreatedAt(now);
143	        refreshTokenRepository.save(newRefreshToken);
144	
145	        return new AuthResponse(newAccessToken, newRefreshTokenStr, user.isForcePasswordReset());
146	    }
147	
148	    public void logout(String refreshTokenStr) {
149	        String tokenHash = hashToken(refreshTokenStr);
150	        refreshTokenRepository.findByTokenHash(tokenHash).ifPresent(token -> {
151	            token.setRevoked(true);
152	            refreshTokenRepository.save(token);
153	        });
154	    }
155	
156	    public void changePassword(Long userId, String oldPass, String newPass) {
157	        User user = userRepository.findById(userId)
158	            .orElseThrow(() -> new EntityNotFoundException("User", userId));
159	
160	        if (!passwordEncoder.matches(oldPass, user.getPasswordHash())) {
161	            throw new BusinessRuleException("Current password is incorrect");
162	        }
163	
164	        validatePasswordStrength(newPass);
165	
166	        user.setPasswordHash(passwordEncoder.encode(newPass));
167	        user.setForcePasswordReset(false);
168	        user.setUpdatedAt(LocalDateTime.now());
169	        userRepository.save(user);
170	
171	        refreshTokenRepository.revokeAllByUserId(userId);
172	    }
173	
174	    private void validatePasswordStrength(String password) {
175	        if (password == null || password.length() < 12) {
176	            throw new BusinessRuleException(
177	                "Password must be at least 12 characters long");
178	        }
179	        if (!password.chars().anyMatch(Character::isUpperCase)) {
180	            throw new BusinessRuleException(
181	                "Password must contain at least one uppercase letter");
182	        }
183	        if (!password.chars().anyMatch(Character::isLowerCase)) {
184	            throw new BusinessRuleException(
185	                "Password must contain at least one lowercase letter");
186	        }
187	        if (!password.chars().anyMatch(Character::isDigit)) {
188	            throw new BusinessRuleException(
189	                "Password must contain at least one digit");
190	        }
191	        if (!password.chars().anyMatch(c -> !Character.isLetterOrDigit(c))) {
192	            throw new BusinessRuleException(
193	                "Password must contain at least one special character");
194	        }
195	    }
196	
197	    private void recordFailedAttempt(String username, String ipAddress, String reason) {
198	        LoginAttempt attempt = new LoginAttempt();
199	        attempt.setUsername(username);
200	        attempt.setIpAddress(ipAddress);
201	        attempt.setSuccess(false);
202	        attempt.setFailureReason(reason);
203	        attempt.setAttemptedAt(LocalDateTime.now());
204	        loginAttemptRepository.save(attempt);
205	    }
206	
207	    private String hashToken(String token) {
208	        try {
209	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
210	            byte[] hash = digest.digest(token.getBytes(StandardCharsets.UTF_8));
211	            return HexFormat.of().formatHex(hash);
212	        } catch (NoSuchAlgorithmException e) {
213	            throw new IllegalStateException("SHA-256 not available", e);
214	        }
215	    }
216	}
