1	package com.reclaim.portal.auth.controller;
2	
3	import com.reclaim.portal.auth.dto.AuthResponse;
4	import com.reclaim.portal.auth.dto.ChangePasswordRequest;
5	import com.reclaim.portal.auth.dto.LoginRequest;
6	import com.reclaim.portal.auth.entity.User;
7	import com.reclaim.portal.auth.repository.UserRepository;
8	import com.reclaim.portal.auth.service.AuthService;
9	import com.reclaim.portal.common.config.ReclaimProperties;
10	import com.reclaim.portal.common.exception.EntityNotFoundException;
11	import jakarta.servlet.http.Cookie;
12	import jakarta.servlet.http.HttpServletRequest;
13	import jakarta.servlet.http.HttpServletResponse;
14	import jakarta.validation.Valid;
15	import org.springframework.http.ResponseCookie;
16	import org.springframework.http.ResponseEntity;
17	import org.springframework.security.core.Authentication;
18	import org.springframework.security.core.userdetails.UserDetails;
19	import org.springframework.web.bind.annotation.*;
20	
21	@RestController
22	@RequestMapping("/api/auth")
23	public class AuthApiController {
24	
25	    private static final String REFRESH_COOKIE_NAME = "refreshToken";
26	    private static final int REFRESH_COOKIE_MAX_AGE = 7 * 24 * 60 * 60; // 7 days in seconds
27	
28	    private final AuthService authService;
29	    private final UserRepository userRepository;
30	    private final ReclaimProperties reclaimProperties;
31	
32	    public AuthApiController(AuthService authService,
33	                             UserRepository userRepository,
34	                             ReclaimProperties reclaimProperties) {
35	        this.authService = authService;
36	        this.userRepository = userRepository;
37	        this.reclaimProperties = reclaimProperties;
38	    }
39	
40	    @PostMapping("/login")
41	    public ResponseEntity<AuthResponse> login(@Valid @RequestBody LoginRequest request,
42	                                              HttpServletRequest httpRequest,
43	                                              HttpServletResponse httpResponse) {
44	        String ipAddress = resolveIpAddress(httpRequest);
45	        AuthResponse authResponse = authService.login(
46	            request.getUsername(), request.getPassword(), ipAddress);
47	
48	        setRefreshCookie(httpResponse, authResponse.getRefreshToken());
49	
50	        AuthResponse responseBody = new AuthResponse(
51	            authResponse.getAccessToken(),
52	            null,
53	            authResponse.isForcePasswordReset()
54	        );
55	        return ResponseEntity.ok(responseBody);
56	    }
57	
58	    @PostMapping("/refresh")
59	    public ResponseEntity<AuthResponse> refresh(HttpServletRequest httpRequest,
60	                                                HttpServletResponse httpResponse) {
61	        validateOrigin(httpRequest);
62	
63	        String refreshTokenStr = extractRefreshCookie(httpRequest);
64	        if (refreshTokenStr == null) {
65	            return ResponseEntity.badRequest().build();
66	        }
67	
68	        AuthResponse authResponse = authService.refresh(refreshTokenStr);
69	        setRefreshCookie(httpResponse, authResponse.getRefreshToken());
70	
71	        AuthResponse responseBody = new AuthResponse(
72	            authResponse.getAccessToken(),
73	            null,
74	            authResponse.isForcePasswordReset()
75	        );
76	        return ResponseEntity.ok(responseBody);
77	    }
78	
79	    @PostMapping("/logout")
80	    public ResponseEntity<Void> logout(HttpServletRequest httpRequest,
81	                                       HttpServletResponse httpResponse) {
82	        validateOrigin(httpRequest);
83	
84	        String refreshTokenStr = extractRefreshCookie(httpRequest);
85	        if (refreshTokenStr != null) {
86	            authService.logout(refreshTokenStr);
87	        }
88	        clearRefreshCookie(httpResponse);
89	        return ResponseEntity.ok().build();
90	    }
91	
92	    @PostMapping("/change-password")
93	    public ResponseEntity<Void> changePassword(@Valid @RequestBody ChangePasswordRequest request,
94	                                               Authentication authentication) {
95	        UserDetails userDetails = (UserDetails) authentication.getPrincipal();
96	        User user = userRepository.findByUsername(userDetails.getUsername())
97	            .orElseThrow(() -> new EntityNotFoundException(
98	                "User not found: " + userDetails.getUsername()));
99	
100	        authService.changePassword(user.getId(), request.getOldPassword(), request.getNewPassword());
101	        return ResponseEntity.ok().build();
102	    }
103	
104	    private void setRefreshCookie(HttpServletResponse response, String refreshToken) {
105	        ResponseCookie cookie = ResponseCookie.from(REFRESH_COOKIE_NAME, refreshToken)
106	            .httpOnly(true)
107	            .secure(reclaimProperties.getSecurity().isCookieSecure())
108	            .path("/api/auth")
109	            .maxAge(REFRESH_COOKIE_MAX_AGE)
110	            .sameSite("Strict")
111	            .build();
112	        response.addHeader("Set-Cookie", cookie.toString());
113	    }
114	
115	    private void clearRefreshCookie(HttpServletResponse response) {
116	        ResponseCookie cookie = ResponseCookie.from(REFRESH_COOKIE_NAME, "")
117	            .httpOnly(true)
118	            .secure(reclaimProperties.getSecurity().isCookieSecure())
119	            .path("/api/auth")
120	            .maxAge(0)
121	            .sameSite("Strict")
122	            .build();
123	        response.addHeader("Set-Cookie", cookie.toString());
124	    }
125	
126	    private String extractRefreshCookie(HttpServletRequest request) {
127	        if (request.getCookies() == null) {
128	            return null;
129	        }
130	        for (Cookie cookie : request.getCookies()) {
131	            if (REFRESH_COOKIE_NAME.equals(cookie.getName())) {
132	                return cookie.getValue();
133	            }
134	        }
135	        return null;
136	    }
137	
138	    private String resolveIpAddress(HttpServletRequest request) {
139	        String xForwardedFor = request.getHeader("X-Forwarded-For");
140	        if (xForwardedFor != null && !xForwardedFor.isBlank()) {
141	            return xForwardedFor.split(",")[0].trim();
142	        }
143	        return request.getRemoteAddr();
144	    }
145	
146	    /**
147	     * Validates the Origin header on cookie-bearing endpoints (refresh, logout) as a
148	     * defence-in-depth CSRF mitigation alongside the SameSite=Strict cookie attribute.
149	     *
150	     * If no Origin header is present the request is allowed — same-origin requests from the
151	     * same page do not always include Origin. Only explicit cross-origin requests that set a
152	     * different Origin are rejected.
153	     */
154	    private void validateOrigin(HttpServletRequest request) {
155	        String origin = request.getHeader("Origin");
156	        if (origin != null && !origin.isEmpty()) {
157	            String expectedOrigin = request.getScheme() + "://" + request.getServerName();
158	            int port = request.getServerPort();
159	            if (port != 80 && port != 443) {
160	                expectedOrigin += ":" + port;
161	            }
162	            if (!origin.equals(expectedOrigin)) {
163	                throw new com.reclaim.portal.common.exception.BusinessRuleException(
164	                    "Cross-origin request rejected");
165	            }
166	        }
167	    }
168	}
