1	package com.reclaim.portal.reviews.service;
2	
3	import com.reclaim.portal.common.exception.BusinessRuleException;
4	import com.reclaim.portal.common.exception.EntityNotFoundException;
5	import com.reclaim.portal.orders.entity.Order;
6	import com.reclaim.portal.orders.repository.OrderRepository;
7	import com.reclaim.portal.reviews.entity.Review;
8	import com.reclaim.portal.reviews.entity.ReviewImage;
9	import com.reclaim.portal.reviews.repository.ReviewImageRepository;
10	import com.reclaim.portal.reviews.repository.ReviewRepository;
11	import com.reclaim.portal.storage.dto.StorageResult;
12	import com.reclaim.portal.storage.service.StorageService;
13	import org.springframework.stereotype.Service;
14	import org.springframework.transaction.annotation.Transactional;
15	import org.springframework.web.multipart.MultipartFile;
16	
17	import java.time.LocalDateTime;
18	import java.util.List;
19	import java.util.Map;
20	
21	@Service
22	public class ReviewService {
23	
24	    private static final String STATUS_COMPLETED = "COMPLETED";
25	    private static final int MAX_IMAGES_PER_REVIEW = 5;
26	    private static final int MAX_REVIEW_TEXT_LENGTH = 1000;
27	    private static final String REVIEWS_SUBDIR = "reviews";
28	
29	    private final ReviewRepository reviewRepository;
30	    private final ReviewImageRepository reviewImageRepository;
31	    private final OrderRepository orderRepository;
32	    private final StorageService storageService;
33	
34	    public ReviewService(ReviewRepository reviewRepository,
35	                         ReviewImageRepository reviewImageRepository,
36	                         OrderRepository orderRepository,
37	                         StorageService storageService) {
38	        this.reviewRepository = reviewRepository;
39	        this.reviewImageRepository = reviewImageRepository;
40	        this.orderRepository = orderRepository;
41	        this.storageService = storageService;
42	    }
43	
44	    /**
45	     * Create a review for a completed order.
46	     * Validates: order exists, order is COMPLETED, no existing review, rating 1-5, text <= 1000 chars.
47	     */
48	    @Transactional
49	    public Review createReview(Long orderId, Long userId, int rating, String reviewText) {
50	        // Validate order exists
51	        Order order = orderRepository.findById(orderId)
52	            .orElseThrow(() -> new EntityNotFoundException("Order", orderId));
53	
54	        // Order must be COMPLETED
55	        if (!STATUS_COMPLETED.equals(order.getOrderStatus())) {
56	            throw new BusinessRuleException(
57	                "Reviews can only be created for completed orders. Current status: "
58	                    + order.getOrderStatus());
59	        }
60	
61	        // Only order owner can review
62	        if (!userId.equals(order.getUserId())) {
63	            throw new BusinessRuleException("Access denied: only the order owner can create a review");
64	        }
65	
66	        // No existing review
67	        if (reviewRepository.existsByOrderId(orderId)) {
68	            throw new BusinessRuleException("A review already exists for order id: " + orderId);
69	        }
70	
71	        // Rating 1-5
72	        if (rating < 1 || rating > 5) {
73	            throw new BusinessRuleException("Rating must be between 1 and 5");
74	        }
75	
76	        // Text length
77	        if (reviewText != null && reviewText.length() > MAX_REVIEW_TEXT_LENGTH) {
78	            throw new BusinessRuleException(
79	                "Review text must not exceed " + MAX_REVIEW_TEXT_LENGTH + " characters");
80	        }
81	
82	        LocalDateTime now = LocalDateTime.now();
83	        Review review = new Review();
84	        review.setOrderId(orderId);
85	        review.setReviewerUserId(userId);
86	        review.setRating(rating);
87	        review.setReviewText(reviewText);
88	        review.setCreatedAt(now);
89	        review.setUpdatedAt(now);
90	
91	        return reviewRepository.save(review);
92	    }
93	
94	    /**
95	     * Add an image to an existing review.
96	     * Validates: review exists, belongs to user, image count < 5.
97	     */
98	    @Transactional
99	    public ReviewImage addReviewImage(Long reviewId, Long userId, MultipartFile file) {
100	        // Validate review exists
101	        Review review = reviewRepository.findById(reviewId)
102	            .orElseThrow(() -> new EntityNotFoundException("Review", reviewId));
103	
104	        // Review must belong to the user
105	        if (!userId.equals(review.getReviewerUserId())) {
106	            throw new BusinessRuleException("You can only add images to your own reviews");
107	        }
108	
109	        // Max 5 images
110	        long imageCount = reviewImageRepository.countByReviewId(reviewId);
111	        if (imageCount >= MAX_IMAGES_PER_REVIEW) {
112	            throw new BusinessRuleException(
113	                "A review cannot have more than " + MAX_IMAGES_PER_REVIEW + " images");
114	        }
115	
116	        // Store the file
117	        StorageResult result = storageService.store(file, REVIEWS_SUBDIR);
118	
119	        ReviewImage image = new ReviewImage();
120	        image.setReviewId(reviewId);
121	        image.setFileName(result.fileName());
122	        image.setFilePath(result.filePath());
123	        image.setContentType(result.contentType());
124	        image.setFileSize(result.fileSize());
125	        image.setChecksum(result.checksum());
126	        image.setDisplayOrder((int) imageCount); // append at end
127	        image.setUploadedAt(LocalDateTime.now());
128	
129	        return reviewImageRepository.save(image);
130	    }
131	
132	    /**
133	     * Get review and associated images for an order.
134	     */
135	    @Transactional(readOnly = true)
136	    public Map<String, Object> getReviewForOrder(Long orderId) {
137	        Review review = reviewRepository.findByOrderId(orderId)
138	            .orElseThrow(() -> new EntityNotFoundException(
139	                "Review not found for order id: " + orderId));
140	        List<ReviewImage> images = reviewImageRepository.findByReviewId(review.getId());
141	        return Map.of("review", review, "images", images);
142	    }
143	
144	    /**
145	     * Get review for an order, enforcing ownership for non-staff callers.
146	     */
147	    @Transactional(readOnly = true)
