22	import java.util.ArrayList;
23	import java.util.List;
24	import java.util.Map;
25	
26	@Service
27	@Transactional
28	public class OrderService {
29	
30	    private static final DateTimeFormatter TIME_FMT = DateTimeFormatter.ofPattern("HH:mm");
31	
32	    private static final String STATUS_PENDING = "PENDING_CONFIRMATION";
33	    private static final String STATUS_ACCEPTED = "ACCEPTED";
34	    private static final String STATUS_COMPLETED = "COMPLETED";
35	    private static final String STATUS_CANCELED = "CANCELED";
36	    private static final String STATUS_EXCEPTION = "EXCEPTION";
37	
38	    private final OrderRepository orderRepository;
39	    private final OrderItemRepository orderItemRepository;
40	    private final OrderOperationLogRepository orderOperationLogRepository;
41	    private final AppointmentService appointmentService;
42	    private final RecyclingItemRepository recyclingItemRepository;
43	
44	    public OrderService(OrderRepository orderRepository,
45	                        OrderItemRepository orderItemRepository,
46	                        OrderOperationLogRepository orderOperationLogRepository,
47	                        AppointmentService appointmentService,
48	                        RecyclingItemRepository recyclingItemRepository) {
49	        this.orderRepository = orderRepository;
50	        this.orderItemRepository = orderItemRepository;
51	        this.orderOperationLogRepository = orderOperationLogRepository;
52	        this.appointmentService = appointmentService;
53	        this.recyclingItemRepository = recyclingItemRepository;
54	    }
55	
56	    /**
57	     * Create a new order: validate appointment, book slot, snapshot items, calculate total.
58	     */
59	    public Order createOrder(Long userId, List<Long> itemIds, Long appointmentId, String appointmentType) {
60	        // Validate appointment exists and has capacity
61	        Appointment appointment = appointmentService.findById(appointmentId);
62	        if (!appointmentType.equals(appointment.getAppointmentType())) {
63	            throw new BusinessRuleException(
64	                "Appointment type mismatch: expected " + appointment.getAppointmentType()
65	                    + " but got " + appointmentType);
66	        }
67	        appointmentService.validateAppointmentTime(
68	            appointment.getAppointmentDate(), appointment.getStartTime());
69	
70	        // Book the slot (throws if no capacity)
71	        appointmentService.bookSlot(appointmentId);
72	
73	        // Create order
74	        LocalDateTime now = LocalDateTime.now();
75	        Order order = new Order();
76	        order.setUserId(userId);
77	        order.setAppointmentId(appointmentId);
78	        order.setOrderStatus(STATUS_PENDING);
79	        order.setAppointmentType(appointmentType);
80	        order.setRescheduleCount(0);
81	        order.setCurrency("USD");
82	        order.setCreatedAt(now);
83	        order.setUpdatedAt(now);
84	        order = orderRepository.save(order);
85	
86	        // Snapshot items
87	        List<RecyclingItem> items = recyclingItemRepository.findAllById(itemIds);
88	        if (items.isEmpty()) {
89	            throw new BusinessRuleException("No valid items found for the provided item ids");
90	        }
91	
92	        BigDecimal total = BigDecimal.ZERO;
93	        List<OrderItem> orderItems = new ArrayList<>();
94	        for (RecyclingItem item : items) {
95	            OrderItem oi = new OrderItem();
96	            oi.setOrderId(order.getId());
97	            oi.setItemId(item.getId());
98	            oi.setSnapshotTitle(item.getTitle());
99	            oi.setSnapshotCategory(item.getCategory());
100	            oi.setSnapshotCondition(item.getItemCondition());
101	            oi.setSnapshotPrice(item.getPrice() != null ? item.getPrice() : BigDecimal.ZERO);
102	            orderItems.add(oi);
103	            if (item.getPrice() != null) {
104	                total = total.add(item.getPrice());
105	            }
106	        }
107	        orderItemRepository.saveAll(orderItems);
108	
109	        order.setTotalPrice(total);
110	        order = orderRepository.save(order);
111	
112	        logOperation(order.getId(), userId, "ORDER_CREATED", null, STATUS_PENDING,
113	            "Order created with " + items.size() + " item(s)");
114	
115	        return order;
116	    }
117	
118	    /**
119	     * Accept a pending order: PENDING_CONFIRMATION -> ACCEPTED.
120	     */
121	    public Order acceptOrder(Long orderId, Long reviewerId) {
122	        Order order = findOrderById(orderId);
123	        requireStatus(order, STATUS_PENDING);
124	
125	        String prev = order.getOrderStatus();
126	        order.setOrderStatus(STATUS_ACCEPTED);
127	        order.setReviewerId(reviewerId);
128	        order.setUpdatedAt(LocalDateTime.now());
129	        order = orderRepository.save(order);
130	
131	        logOperation(orderId, reviewerId, "ORDER_ACCEPTED", prev, STATUS_ACCEPTED, null);
132	        return order;
133	    }
134	
135	    /**
136	     * Complete an accepted order: ACCEPTED -> COMPLETED.
137	     */
138	    public Order completeOrder(Long orderId, Long actorId) {
139	        Order order = findOrderById(orderId);
140	        requireStatus(order, STATUS_ACCEPTED);
141	
142	        String prev = order.getOrderStatus();
143	        order.setOrderStatus(STATUS_COMPLETED);
144	        order.setUpdatedAt(LocalDateTime.now());
145	        order = orderRepository.save(order);
146	
147	        logOperation(orderId, actorId, "ORDER_COMPLETED", prev, STATUS_COMPLETED, null);
148	        return order;
149	    }
150	
151	    /**
152	     * Cancel an order. If the appointment is less than 1 hour away, flag as EXCEPTION instead.
153	     * Only the order owner may request cancellation.
154	     */
155	    public Order cancelOrder(Long orderId, Long actorId, String reason) {
156	        Order order = findOrderById(orderId);
157	        if (actorId == null || !actorId.equals(order.getUserId())) {
158	            throw new BusinessRuleException("Access denied");
159	        }
160	        if (!STATUS_PENDING.equals(order.getOrderStatus())
161	                && !STATUS_ACCEPTED.equals(order.getOrderStatus())) {
162	            throw new BusinessRuleException(
163	                "Cannot cancel order in status: " + order.getOrderStatus());
164	        }
165	
166	        // Determine if appointment is < 1 hr away
167	        Appointment appointment = appointmentService.findById(order.getAppointmentId());
168	        LocalTime startTime = LocalTime.parse(appointment.getStartTime(), TIME_FMT);
169	        LocalDateTime appointmentDateTime = appointment.getAppointmentDate().atTime(startTime);
170	        LocalDateTime now = LocalDateTime.now();
171	        boolean tooClose = appointmentDateTime.isBefore(now.plusHours(1));
172	
173	        String prev = order.getOrderStatus();
174	
175	        if (tooClose) {
176	            // Flag as exception - requires admin approval to proceed
177	            order.setOrderStatus(STATUS_EXCEPTION);
178	            order.setCancellationReason(reason);
179	            order.setUpdatedAt(now);
180	            order = orderRepository.save(order);
181	            logOperation(orderId, actorId, "CANCEL_REQUESTED", prev, STATUS_EXCEPTION,
182	                "Cancellation requested within 1 hour of appointment: " + reason);
183	        } else {
184	            order.setOrderStatus(STATUS_CANCELED);
185	            order.setCancellationReason(reason);
186	            order.setUpdatedAt(now);
187	            order = orderRepository.save(order);
188	            appointmentService.releaseSlot(order.getAppointmentId());
189	            logOperation(orderId, actorId, "ORDER_CANCELED", prev, STATUS_CANCELED, reason);
190	        }
191	
192	        return order;
193	    }
194	
195	    /**
196	     * Approve a cancellation that was flagged as EXCEPTION: EXCEPTION -> CANCELED.
197	     */
198	    public Order approveCancellation(Long orderId, Long reviewerId, String reason) {
199	        Order order = findOrderById(orderId);
200	        requireStatus(order, STATUS_EXCEPTION);
201	
202	        String prev = order.getOrderStatus();
203	        order.setOrderStatus(STATUS_CANCELED);
204	        order.setCancellationApprovedBy(reviewerId);
205	        order.setCancellationReason(reason != null ? reason : order.getCancellationReason());
206	        order.setUpdatedAt(LocalDateTime.now());
207	        order = orderRepository.save(order);
208	
209	        appointmentService.releaseSlot(order.getAppointmentId());
210	        logOperation(orderId, reviewerId, "CANCEL_APPROVED", prev, STATUS_CANCELED,
211	            "Cancellation approved by reviewer " + reviewerId);
212	
213	        return order;
214	    }
215	
216	    /**
217	     * Reschedule an order to a new appointment slot.
218	     * Requires: PENDING or ACCEPTED, rescheduleCount < 2.
219	     * Only the order owner may reschedule.
220	     */
221	    public Order rescheduleOrder(Long orderId, Long actorId, Long newAppointmentId) {
222	        Order order = findOrderById(orderId);
223	        if (actorId == null || !actorId.equals(order.getUserId())) {
224	            throw new BusinessRuleException("Access denied");
225	        }
226	        if (!STATUS_PENDING.equals(order.getOrderStatus())
227	                && !STATUS_ACCEPTED.equals(order.getOrderStatus())) {
228	            throw new BusinessRuleException(
229	                "Cannot reschedule order in status: " + order.getOrderStatus());
230	        }
231	        if (order.getRescheduleCount() >= 2) {
232	            throw new BusinessRuleException("Order has already been rescheduled the maximum number of times (2)");
233	        }
234	
235	        // Validate the new appointment
236	        Appointment newAppointment = appointmentService.findById(newAppointmentId);
237	        appointmentService.validateAppointmentTime(
238	            newAppointment.getAppointmentDate(), newAppointment.getStartTime());
239	
240	        Long oldAppointmentId = order.getAppointmentId();
241	
242	        // Release old slot and book new one
243	        appointmentService.releaseSlot(oldAppointmentId);
244	        appointmentService.bookSlot(newAppointmentId);
245	
246	        String prev = order.getOrderStatus();
247	        order.setAppointmentId(newAppointmentId);
248	        order.setRescheduleCount(order.getRescheduleCount() + 1);
249	        order.setUpdatedAt(LocalDateTime.now());
250	        order = orderRepository.save(order);
251	
252	        logOperation(orderId, actorId, "ORDER_RESCHEDULED", prev, order.getOrderStatus(),
253	            "Rescheduled from appointment " + oldAppointmentId + " to " + newAppointmentId);
254	
255	        return order;
256	    }
257	
