268	    /**
269	     * Authorization helper: verifies that the actor is allowed to access an order.
270	     * Staff (isStaff=true) may always access. Otherwise, actorId must equal the order owner.
271	     * Also allows the assigned reviewer to view.
272	     */
273	    public void requireOrderOwnerOrStaff(Order order, Long actorId, boolean isStaff) {
274	        if (isStaff) {
275	            return;
276	        }
277	        if (actorId != null && actorId.equals(order.getUserId())) {
278	            return;
279	        }
280	        if (actorId != null && actorId.equals(order.getReviewerId())) {
281	            return;
282	        }
