298	    /** Backward-compatible variant used by internal/test callers — no ownership check. */
299	    @Transactional(readOnly = true)
300	    public Map<String, Object> getOrderWithLogs(Long orderId) {
301	        Order order = findOrderById(orderId);
302	        List<OrderItem> items = orderItemRepository.findByOrderId(orderId);
303	        List<OrderOperationLog> logs = orderOperationLogRepository
304	            .findByOrderIdOrderByCreatedAtAsc(orderId);
