314	    private void requireStatus(Order order, String expectedStatus) {
315	        if (!expectedStatus.equals(order.getOrderStatus())) {
316	            throw new BusinessRuleException(
317	                "Expected order status " + expectedStatus + " but found " + order.getOrderStatus());
318	        }
