24	
25	@Service
26	@Transactional
27	public class CatalogService {
28	
29	    private final RecyclingItemRepository recyclingItemRepository;
30	    private final ItemFingerprintRepository itemFingerprintRepository;
31	    private final SearchLogRepository searchLogRepository;
32	    private final SearchClickLogRepository searchClickLogRepository;
33	    private final SearchService searchService;
