35	
36	    public CatalogService(RecyclingItemRepository recyclingItemRepository,
37	                          ItemFingerprintRepository itemFingerprintRepository,
38	                          SearchLogRepository searchLogRepository,
39	                          SearchClickLogRepository searchClickLogRepository,
40	                          SearchService searchService,
41	                          RankingService rankingService) {
42	        this.recyclingItemRepository = recyclingItemRepository;
43	        this.itemFingerprintRepository = itemFingerprintRepository;
44	        this.searchLogRepository = searchLogRepository;
45	        this.searchClickLogRepository = searchClickLogRepository;
46	        this.searchService = searchService;
47	        this.rankingService = rankingService;
