49	
50	    public List<RecyclingItem> searchItems(String keyword, String category, String condition,
51	                                           BigDecimal minPrice, BigDecimal maxPrice, Long userId) {
52	        List<RecyclingItem> results;
53	        try {
54	            results = recyclingItemRepository.searchItemsFullText(keyword, category, condition, minPrice, maxPrice);
55	        } catch (Exception e) {
56	            // Fallback to LIKE search (H2 or when full-text index not available)
57	            results = recyclingItemRepository.searchItems(keyword, category, condition, minPrice, maxPrice);
58	        }
59	
60	        if (keyword != null && !keyword.isBlank()) {
61	            searchService.updateTrends(keyword);
62	        }
63	
64	        List<RecyclingItem> rankedResults = rankingService.rankItems(results, userId);
65	
66	        SearchLog log = new SearchLog();
67	        log.setUserId(userId);
68	        log.setSearchTerm(keyword);
69	        log.setCategoryFilter(category);
70	        log.setConditionFilter(condition);
71	        log.setMinPrice(minPrice);
72	        log.setMaxPrice(maxPrice);
73	        log.setResultCount(rankedResults.size());
74	        log.setSearchedAt(LocalDateTime.now());
75	        searchLogRepository.save(log);
76	
77	        return rankedResults;
78	    }
