208	    public ContractInstance signContract(Long instanceId, Long signerId,
209	                                         String signatureType, byte[] sigData) {
210	        ContractInstance instance = loadInstance(instanceId);
211	        // Only the contract's user may sign
212	        if (signerId == null || !signerId.equals(instance.getUserId())) {
213	            throw new BusinessRuleException("Access denied to contract");
214	        }
215	        requireStatus(instance, STATUS_CONFIRMED);
216	
217	        // Salt the signature hash for storage security
218	        String salt = java.util.UUID.randomUUID().toString();
219	        String encodedSig = java.util.Base64.getEncoder().encodeToString(sigData);
220	        String signatureHash = sha256Hex((salt + ":" + encodedSig).getBytes(java.nio.charset.StandardCharsets.UTF_8));
221	
222	        // Wrap bytes as a MultipartFile for StorageService
223	        MultipartFile sigFile = new ByteArrayMultipartFile(
224	                "signature",
225	                "signature_" + signerId + ".png",
226	                "image/png",
227	                sigData
228	        );
229	
230	        StorageResult result = storageService.store(sigFile, "signatures");
231	
232	        SignatureArtifact artifact = new SignatureArtifact();
233	        artifact.setContractId(instanceId);
234	        artifact.setSignerId(signerId);
235	        artifact.setSignatureType(signatureType);
236	        artifact.setFilePath(result.filePath());
237	        artifact.setSignatureHash(salt + ":" + signatureHash);
238	        artifact.setChecksum(result.checksum());
239	        artifact.setSignedAt(LocalDateTime.now());
240	        signatureRepository.save(artifact);
241	
242	        instance.setContractStatus(STATUS_SIGNED);
243	        instance.setSignedAt(LocalDateTime.now());
244	        instance.setUpdatedAt(LocalDateTime.now());
245	        return instanceRepository.save(instance);
246	    }
