40	        ReclaimProperties.Appointments cfg = reclaimProperties.getAppointments();
41	        LocalDateTime now = LocalDateTime.now();
42	        LocalDate today = now.toLocalDate();
43	
44	        LocalDate minDate = today.plusDays(0);
45	        LocalDate maxDate = today.plusDays(cfg.getMaxAdvanceDays());
46	
47	        if (date.isBefore(minDate) || date.isAfter(maxDate)) {
48	            throw new BusinessRuleException(
49	                "Appointment date must be between today and " + cfg.getMaxAdvanceDays() + " days from now");
50	        }
51	
52	        // Auto-generate slots for the day if none exist yet
53	        generateSlots(date);
54	
55	        List<Appointment> slots = appointmentRepository
56	            .findByAppointmentDateAndAppointmentType(date, type);
57	
58	        LocalDateTime minAllowed = now.plusHours(cfg.getMinAdvanceHours());
59	
60	        return slots.stream()
61	            .filter(a -> a.getSlotsBooked() < a.getSlotsAvailable())
62	            .filter(a -> {
63	                // For today specifically, also check that start time is after now+minAdvanceHours
64	                if (date.equals(today)) {
65	                    LocalTime slotStart = LocalTime.parse(a.getStartTime(), TIME_FMT);
66	                    LocalDateTime slotDateTime = date.atTime(slotStart);
67	                    return !slotDateTime.isBefore(minAllowed);
68	                }
69	                return true;
70	            })
71	            .collect(Collectors.toList());
72	    }
73	
74	    /**
75	     * Generate 30-minute slots for a date if none exist yet.
76	     */
77	    @Transactional
78	    public void generateSlots(LocalDate date) {
79	        if (appointmentRepository.countByAppointmentDate(date) > 0) {
80	            return;
81	        }
82	
83	        ReclaimProperties.Appointments cfg = reclaimProperties.getAppointments();
84	        List<Appointment> toSave = new ArrayList<>();
85	
86	        LocalTime cursor = LocalTime.of(cfg.getBusinessStartHour(), 0);
87	        LocalTime end = LocalTime.of(cfg.getBusinessEndHour(), 0);
88	
89	        while (cursor.isBefore(end)) {
90	            LocalTime slotEnd = cursor.plusMinutes(cfg.getSlotMinutes());
91	            if (slotEnd.isAfter(end)) {
92	                break;
93	            }
94	
95	            for (String type : List.of(PICKUP, DROPOFF)) {
96	                Appointment a = new Appointment();
97	                a.setAppointmentDate(date);
98	                a.setStartTime(cursor.format(TIME_FMT));
99	                a.setEndTime(slotEnd.format(TIME_FMT));
100	                a.setAppointmentType(type);
101	                a.setSlotsAvailable(PICKUP.equals(type)
102	                    ? cfg.getPickupCapacity()
103	                    : cfg.getDropoffCapacity());
104	                a.setSlotsBooked(0);
105	                a.setCreatedAt(LocalDateTime.now());
106	                toSave.add(a);
107	            }
108	
109	            cursor = slotEnd;
110	        }
111	
112	        appointmentRepository.saveAll(toSave);
113	    }
114	
115	    /**
116	     * Increment slotsBooked for the given appointment after checking capacity.
117	     */
118	    @Transactional
119	    public Appointment bookSlot(Long appointmentId) {
120	        Appointment appointment = findById(appointmentId);
121	        if (appointment.getSlotsBooked() >= appointment.getSlotsAvailable()) {
122	            throw new BusinessRuleException("No available capacity for appointment id: " + appointmentId);
123	        }
124	        appointment.setSlotsBooked(appointment.getSlotsBooked() + 1);
125	        return appointmentRepository.save(appointment);
126	    }
127	
128	    /**
129	     * Decrement slotsBooked (minimum 0) for the given appointment.
130	     */
131	    @Transactional
132	    public Appointment releaseSlot(Long appointmentId) {
133	        Appointment appointment = findById(appointmentId);
134	        int current = appointment.getSlotsBooked();
135	        appointment.setSlotsBooked(Math.max(0, current - 1));
136	        return appointmentRepository.save(appointment);
137	    }
138	
139	    /**
140	     * Validate that a date+startTime combination satisfies advance booking constraints.
141	     */
142	    public void validateAppointmentTime(LocalDate date, String startTime) {
143	        ReclaimProperties.Appointments cfg = reclaimProperties.getAppointments();
144	        LocalDateTime now = LocalDateTime.now();
145	
146	        LocalTime time = LocalTime.parse(startTime, TIME_FMT);
147	        LocalDateTime appointmentDateTime = date.atTime(time);
148	
149	        LocalDateTime minAllowed = now.plusHours(cfg.getMinAdvanceHours());
150	        LocalDateTime maxAllowed = now.plusDays(cfg.getMaxAdvanceDays());
151	
152	        if (appointmentDateTime.isBefore(minAllowed)) {
153	            throw new BusinessRuleException(
154	                "Appointment must be at least " + cfg.getMinAdvanceHours() + " hours in advance");
155	        }
156	        if (appointmentDateTime.isAfter(maxAllowed)) {
157	            throw new BusinessRuleException(
158	                "Appointment cannot be more than " + cfg.getMaxAdvanceDays() + " days in advance");
159	        }
160	    }
161	
162	    public Appointment findById(Long id) {
163	        return appointmentRepository.findById(id)
164	            .orElseThrow(() -> new EntityNotFoundException("Appointment", id));
165	    }
166	}
