1	/* ============================================================
2	   ReClaim Portal — app.js
3	   Utilities: JWT, fetch wrapper, autocomplete, star rating,
4	   image upload, canvas signature, slot loader, form validation,
5	   logout handler.
6	   ============================================================ */
7	
8	'use strict';
9	
10	/* ── Token management (in-memory) ────────────────────────────
11	   Tokens are intentionally kept in memory only; sessionStorage
12	   is used as a secondary persistence within the same tab for
13	   page navigations (not across tabs).
14	   ─────────────────────────────────────────────────────────── */
15	const TokenStore = (() => {
16	    let _token = null;
17	
18	    function get() {
19	        if (_token) return _token;
20	        try { _token = sessionStorage.getItem('accessToken') || null; } catch (_) {}
21	        return _token;
22	    }
23	
24	    function set(token) {
25	        _token = token;
26	        try { sessionStorage.setItem('accessToken', token); } catch (_) {}
27	    }
28	
29	    function clear() {
30	        _token = null;
31	        try { sessionStorage.removeItem('accessToken'); } catch (_) {}
32	    }
33	
34	    return { get, set, clear };
35	})();
36	
37	/* ── Fetch wrapper ───────────────────────────────────────────
38	   Automatically attaches Authorization header when token exists.
39	   Handles 401 by redirecting to /login.
40	   ─────────────────────────────────────────────────────────── */
41	async function apiFetch(url, options = {}) {
42	    const token = TokenStore.get();
43	    const headers = Object.assign({}, options.headers || {});
44	
45	    if (token) {
46	        headers['Authorization'] = 'Bearer ' + token;
47	    }
48	
49	    if (!(options.body instanceof FormData) && !headers['Content-Type']) {
50	        if (options.body && typeof options.body === 'string') {
51	            headers['Content-Type'] = 'application/json';
52	        }
53	    }
54	
55	    const response = await fetch(url, Object.assign({}, options, { headers }));
56	
57	    if (response.status === 401) {
58	        TokenStore.clear();
59	        window.location.href = '/login';
60	        throw new Error('Unauthorized — redirecting to login');
61	    }
62	
63	    return response;
64	}
65	
66	/* ── Logout handler ─────────────────────────────────────────── */
67	function initLogout() {
68	    document.querySelectorAll('[data-action="logout"]').forEach(el => {
69	        el.addEventListener('click', async function (e) {
70	            e.preventDefault();
71	            try {
72	                await apiFetch('/api/auth/logout', { method: 'POST' });
73	            } catch (_) { /* ignore network errors */ }
74	            TokenStore.clear();
75	            window.location.href = '/login';
76	        });
77	    });
78	}
79	
80	/* ── Debounce ────────────────────────────────────────────────── */
81	function debounce(fn, ms) {
82	    let timer;
83	    return function (...args) {
84	        clearTimeout(timer);
85	        timer = setTimeout(() => fn.apply(this, args), ms);
86	    };
87	}
88	
89	/* ── Autocomplete ────────────────────────────────────────────── */
90	function initAutocomplete(inputEl, listEl, endpoint) {
91	    if (!inputEl || !listEl) return;
92	
93	    let activeIndex = -1;
94	
95	    const fetchSuggestions = debounce(async function (q) {
96	        if (!q || q.length < 2) {
97	            closeList();
98	            return;
99	        }
100	        try {
101	            const res = await apiFetch(`${endpoint}?q=${encodeURIComponent(q)}&limit=8`);
102	            if (!res.ok) { closeList(); return; }
103	            const suggestions = await res.json(); // expected: string[]
104	            renderList(suggestions, q);
105	        } catch (_) { closeList(); }
106	    }, 280);
107	
108	    inputEl.addEventListener('input', function () {
109	        activeIndex = -1;
110	        fetchSuggestions(this.value.trim());
111	    });
112	
113	    inputEl.addEventListener('keydown', function (e) {
114	        const items = listEl.querySelectorAll('.autocomplete-item');
115	        if (!items.length) return;
116	
117	        if (e.key === 'ArrowDown') {
118	            e.preventDefault();
119	            activeIndex = Math.min(activeIndex + 1, items.length - 1);
120	            highlightItem(items);
121	        } else if (e.key === 'ArrowUp') {
122	            e.preventDefault();
123	            activeIndex = Math.max(activeIndex - 1, 0);
124	            highlightItem(items);
125	        } else if (e.key === 'Enter' && activeIndex >= 0) {
126	            e.preventDefault();
127	            items[activeIndex].click();
128	        } else if (e.key === 'Escape') {
129	            closeList();
130	        }
131	    });
132	
133	    document.addEventListener('click', function (e) {
134	        if (!inputEl.contains(e.target) && !listEl.contains(e.target)) {
135	            closeList();
136	        }
137	    });
138	
139	    function highlightItem(items) {
140	        items.forEach((it, i) => it.classList.toggle('highlighted', i === activeIndex));
141	    }
142	
143	    function renderList(suggestions, q) {
144	        listEl.innerHTML = '';
145	        if (!suggestions.length) { closeList(); return; }
146	        suggestions.forEach(s => {
147	            const div = document.createElement('div');
148	            div.className = 'autocomplete-item';
149	            // Bold the matching part
150	            const esc = q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
151	            div.innerHTML = s.replace(new RegExp(`(${esc})`, 'i'), '<strong>$1</strong>');
152	            div.addEventListener('click', function () {
153	                inputEl.value = s;
154	                closeList();
155	                inputEl.dispatchEvent(new Event('autocomplete-select', { bubbles: true }));
156	            });
157	            listEl.appendChild(div);
158	        });
159	        listEl.classList.add('open');
160	    }
161	
162	    function closeList() {
163	        listEl.innerHTML = '';
164	        listEl.classList.remove('open');
165	        activeIndex = -1;
166	    }
167	}
168	
169	/* ── Star rating click handler ───────────────────────────────── */
170	function initStarRating(containerEl) {
171	    if (!containerEl) return;
172	    // Works with the CSS-only reverse flex approach:
173	    // <div class="star-rating">
174	    //   <input type="radio" id="s5" name="rating" value="5"><label for="s5"></label>
175	    //   ... (5 down to 1)
176	    // </div>
177	    // No JS needed for CSS-only version, but this adds accessible keyboard support.
178	    const inputs = containerEl.querySelectorAll('input[type="radio"]');
179	    inputs.forEach(input => {
180	        input.addEventListener('change', function () {
181	            containerEl.dataset.value = this.value;
182	        });
183	    });
184	}
185	
186	/* ── Image upload validation ─────────────────────────────────── */
187	function initImageUpload(uploadZoneEl, previewsEl, hiddenInputEl) {
188	    if (!uploadZoneEl) return;
189	
190	    const MAX_FILES = 5;
191	    const MAX_SIZE  = 3 * 1024 * 1024; // 3 MB
192	    const ALLOWED   = ['image/jpeg', 'image/png'];
193	
194	    let files = [];
195	
196	    const fileInput = uploadZoneEl.querySelector('input[type="file"]');
197	    if (!fileInput) return;
198	
199	    fileInput.addEventListener('change', handleFiles);
200	
201	    uploadZoneEl.addEventListener('dragover', e => {
202	        e.preventDefault();
203	        uploadZoneEl.classList.add('drag-over');
204	    });
205	    uploadZoneEl.addEventListener('dragleave', () => uploadZoneEl.classList.remove('drag-over'));
206	    uploadZoneEl.addEventListener('drop', e => {
207	        e.preventDefault();
208	        uploadZoneEl.classList.remove('drag-over');
209	        handleFiles({ target: { files: e.dataTransfer.files } });
210	    });
211	
212	    function handleFiles(e) {
213	        const incoming = Array.from(e.target.files || []);
214	        const errors = [];
215	
216	        incoming.forEach(f => {
217	            if (files.length >= MAX_FILES) {
218	                errors.push(`Maximum ${MAX_FILES} images allowed.`);
219	                return;
220	            }
221	            if (!ALLOWED.includes(f.type)) {
222	                errors.push(`${f.name}: only JPG and PNG are accepted.`);
223	                return;
224	            }
225	            if (f.size > MAX_SIZE) {
226	                errors.push(`${f.name}: exceeds 3 MB limit.`);
227	                return;
228	            }
229	            files.push(f);
230	        });
231	
232	        if (errors.length) {
233	            showUploadError(errors.join(' '));
234	        }
235	
236	        renderPreviews();
237	        syncHiddenInput();
238	        fileInput.value = '';
239	    }
240	
241	    function renderPreviews() {
242	        if (!previewsEl) return;
243	        previewsEl.innerHTML = '';
244	        files.forEach((f, i) => {
245	            const wrap = document.createElement('div');
246	            wrap.className = 'upload-preview-item';
247	
248	            const img = document.createElement('img');
249	            img.src = URL.createObjectURL(f);
250	            img.alt = f.name;
251	            wrap.appendChild(img);
252	
253	            const btn = document.createElement('button');
254	            btn.type = 'button';
