373	/* ── Appointment slot loader ─────────────────────────────────── */
374	function initSlotLoader(dateInputEl, typeGroupEl, gridEl, hiddenSlotEl) {
375	    if (!dateInputEl || !gridEl) return;
376	
377	    async function loadSlots() {
378	        const date = dateInputEl.value;
379	        if (!date) return;
380	
381	        const type = typeGroupEl
382	            ? (typeGroupEl.querySelector('.toggle-option.active')?.dataset.value || 'OFFLINE')
383	            : 'OFFLINE';
384	
385	        gridEl.innerHTML = '<div class="text-muted mono" style="font-size:.7rem;padding:.5rem;">Loading slots…</div>';
386	
387	        try {
388	            const res = await apiFetch(
389	                `/api/appointments/available?date=${encodeURIComponent(date)}&type=${encodeURIComponent(type)}`
390	            );
391	            if (!res.ok) throw new Error('Failed to load slots');
392	            const slots = await res.json(); // expected: [{ id, startTime, endTime, available }]
393	            renderSlots(slots);
394	        } catch (_) {
395	            gridEl.innerHTML = '<div class="text-error mono" style="font-size:.7rem;padding:.5rem;">Failed to load slots.</div>';
396	        }
397	    }
398	
399	    function renderSlots(slots) {
400	        gridEl.innerHTML = '';
401	        if (!slots.length) {
402	            gridEl.innerHTML = '<div class="text-muted mono" style="font-size:.7rem;padding:.5rem;">No slots available.</div>';
403	            return;
404	        }
405	        slots.forEach(s => {
406	            const div = document.createElement('div');
407	            div.className = 'slot-item' + (s.available === false ? ' slot-taken' : '');
408	            div.textContent = formatSlotTime(s.startTime) + ' – ' + formatSlotTime(s.endTime);
409	            div.dataset.slotId = s.id;
410	            if (s.available !== false) {
411	                div.addEventListener('click', function () {
412	                    gridEl.querySelectorAll('.slot-item').forEach(el => el.classList.remove('slot-selected'));
413	                    this.classList.add('slot-selected');
414	                    if (hiddenSlotEl) hiddenSlotEl.value = s.id;
415	                });
416	            }
417	            gridEl.appendChild(div);
418	        });
419	    }
420	
421	    function formatSlotTime(t) {
422	        if (!t) return '';
423	        // t may be "HH:mm:ss" or ISO
424	        const parts = t.split(':');
425	        if (parts.length >= 2) {
426	            let h = parseInt(parts[0], 10);
427	            const m = parts[1].padStart(2, '0');
428	            const ampm = h >= 12 ? 'PM' : 'AM';
429	            h = h % 12 || 12;
430	            return `${h}:${m} ${ampm}`;
431	        }
432	        return t;
433	    }
434	
435	    dateInputEl.addEventListener('change', loadSlots);
436	
437	    if (typeGroupEl) {
438	        typeGroupEl.querySelectorAll('.toggle-option').forEach(btn => {
439	            btn.addEventListener('click', function () {
440	                typeGroupEl.querySelectorAll('.toggle-option').forEach(b => b.classList.remove('active'));
441	                this.classList.add('active');
442	                loadSlots();
443	            });
444	        });
445	    }
446	}
