55	
56	        RankingStrategyVersion strategy = strategyOpt.get();
57	        BigDecimal creditScoreWeight = orZero(strategy.getCreditScoreWeight());
58	        BigDecimal positiveRateWeight = orZero(strategy.getPositiveRateWeight());
59	        BigDecimal reviewQualityWeight = orZero(strategy.getReviewQualityWeight());
60	        BigDecimal minCreditScore = strategy.getMinCreditScoreThreshold();
61	        BigDecimal minPositiveRate = strategy.getMinPositiveRateThreshold();
62	
63	        // Build category affinity from user's completed orders
64	        Set<String> affinityCategories = new HashSet<>();
65	        if (userId != null) {
66	            List<Order> completed = orderRepository.findByUserId(userId).stream()
67	                .filter(o -> "COMPLETED".equals(o.getOrderStatus()))
68	                .toList();
69	            for (Order o : completed) {
70	                orderItemRepository.findByOrderId(o.getId()).stream()
71	                    .map(OrderItem::getSnapshotCategory)
72	                    .filter(c -> c != null)
73	                    .forEach(affinityCategories::add);
74	            }
75	        }
76	
77	        List<ScoredItem> qualifiedItems = new ArrayList<>();
78	        List<RecyclingItem> noSellerItems = new ArrayList<>();
79	
80	        for (RecyclingItem item : items) {
81	            if (item.getSellerId() == null) {
82	                noSellerItems.add(item);
83	                continue;
84	            }
85	
86	            Optional<SellerMetrics> metricsOpt = sellerMetricsRepository.findBySellerId(item.getSellerId());
87	            if (metricsOpt.isEmpty()) {
88	                noSellerItems.add(item);
89	                continue;
90	            }
91	
92	            SellerMetrics metrics = metricsOpt.get();
93	            BigDecimal creditScore = orZero(metrics.getCreditScore());
94	            BigDecimal positiveRate = orZero(metrics.getPositiveRate());
95	            BigDecimal reviewQuality = orZero(metrics.getRecentReviewQuality());
96	
97	            // Filter items below thresholds
98	            if (minCreditScore != null && creditScore.compareTo(minCreditScore) < 0) {
99	                continue;
100	            }
101	            if (minPositiveRate != null && positiveRate.compareTo(minPositiveRate) < 0) {
102	                continue;
103	            }
104	
105	            // score = creditScore*weight + positiveRate*100*weight + recentReviewQuality*weight
106	            BigDecimal score = creditScore.multiply(creditScoreWeight)
107	                    .add(positiveRate.multiply(BigDecimal.valueOf(100)).multiply(positiveRateWeight))
108	                    .add(reviewQuality.multiply(reviewQualityWeight));
109	
110	            // Apply local behavior signal: boost items with more clicks (log scale to avoid domination)
111	            long clicks = clickLogRepository.countByItemId(item.getId());
112	            score = score.add(BigDecimal.valueOf(Math.log1p(clicks) * 0.5));
113	
114	            // Category affinity: boost items in categories the user has completed orders for
115	            if (affinityCategories.contains(item.getCategory())) {
116	                score = score.add(BigDecimal.valueOf(2.0));
117	            }
118	
119	            qualifiedItems.add(new ScoredItem(item, score));
120	        }
121	
122	        qualifiedItems.sort(Comparator.comparing(ScoredItem::score).reversed());
123	
124	        // Sort no-seller items with affinity-matching ones first
125	        final Set<String> finalAffinityCategories = affinityCategories;
126	        noSellerItems.sort(Comparator.comparingInt(
127	            (RecyclingItem i) -> finalAffinityCategories.contains(i.getCategory()) ? 0 : 1));
128	
129	        List<RecyclingItem> ranked = new ArrayList<>(qualifiedItems.size() + noSellerItems.size());
130	        for (ScoredItem si : qualifiedItems) {
131	            ranked.add(si.item());
132	        }
133	        ranked.addAll(noSellerItems);
134	        return ranked;
135	    }
136	
137	    private BigDecimal orZero(BigDecimal value) {
138	        return value == null ? BigDecimal.ZERO : value;
139	    }
140	
141	    private record ScoredItem(RecyclingItem item, BigDecimal score) {
142	    }
143	}
