95	    public String checkDuplicate(String title, String attributes) {
96	        String normalizedTitle = title == null ? "" : title.toLowerCase().trim().replaceAll("\\s+", " ");
97	        String combined = normalizedTitle + (attributes == null ? "" : attributes);
98	        String hash = sha256(combined);
99	
100	        if (itemFingerprintRepository.findByFingerprintHash(hash).isPresent()) {
101	            return "EXACT_DUPLICATE";
102	        }
103	
104	        List<RecyclingItem> sameTitle = recyclingItemRepository.findByNormalizedTitle(normalizedTitle);
105	        if (!sameTitle.isEmpty()) {
106	            return "NEAR_DUPLICATE";
107	        }
108	
109	        return "UNIQUE";
110	    }
111	
112	    private String sha256(String input) {
113	        try {
114	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
115	            byte[] hash = digest.digest(input.getBytes(StandardCharsets.UTF_8));
116	            return HexFormat.of().formatHex(hash);
117	        } catch (NoSuchAlgorithmException e) {
118	            throw new IllegalStateException("SHA-256 not available", e);
119	        }
120	    }
121	}
