303	    /**
304	     * Computes the effective display status of a contract instance.
305	     * Terminal/explicit states are returned as-is; date-based transitions are applied
306	     * to SIGNED/ACTIVE/RENEWED contracts.
307	     */
308	    public String getContractStatus(ContractInstance instance) {
309	        String stored = instance.getContractStatus();
310	
311	        if (STATUS_TERMINATED.equals(stored) || STATUS_VOIDED.equals(stored)
312	                || STATUS_ARCHIVED.equals(stored)) {
313	            return stored;
314	        }
315	        if (STATUS_RENEWED.equals(stored)) {
316	            return STATUS_RENEWED;
317	        }
318	
319	        LocalDate today = LocalDate.now();
320	        LocalDate endDate = instance.getEndDate();
321	
322	        if (endDate != null) {
323	            if (endDate.isBefore(today)) {
324	                return STATUS_TERMINATED;
325	            }
326	            int expiringSoonDays = reclaimProperties.getContracts().getExpiringSoonDays();
327	            if (endDate.isBefore(today.plusDays(expiringSoonDays))) {
328	                return STATUS_EXPIRING_SOON;
329	            }
330	        }
331	
332	        return STATUS_ACTIVE;
333	    }
