391	        ContractInstance instance = loadInstance(contractId);
392	        requireContractAccess(instance, actorId, isStaff);
393	        return evidenceFileRepository.findByEntityTypeAndEntityId("CONTRACT", contractId);
394	    }
395	
396	    // =========================================================================
397	    // Internal helpers
398	    // =========================================================================
399	
400	    private ContractInstance loadInstance(Long id) {
401	        return instanceRepository.findById(id)
402	                .orElseThrow(() -> new EntityNotFoundException("ContractInstance", id));
403	    }
404	
405	    private void requireStatus(ContractInstance instance, String required) {
406	        if (!required.equals(instance.getContractStatus())) {
407	            throw new BusinessRuleException(
408	                    "Expected contract status " + required + " but was " + instance.getContractStatus());
409	        }
410	    }
411	
412	    /**
413	     * Replaces {{fieldName}} placeholders in the template content with values from
414	     * the provided fieldValues JSON-like string (treated as a simple key=value pair map).
415	     * Falls back to the field's defaultValue if no value is provided.
416	     */
417	    private String renderContent(String templateContent, String fieldValuesJson,
418	                                 List<ContractClauseField> fields) {
419	        if (templateContent == null) return "";
420	
421	        // Parse a naive key=value format: "key1=val1,key2=val2"
422	        Map<String, String> values = parseFieldValues(fieldValuesJson);
423	
424	        String rendered = templateContent;
425	        for (ContractClauseField field : fields) {
426	            String placeholder = "{{" + field.getFieldName() + "}}";
427	            String value = values.getOrDefault(field.getFieldName(),
428	                    field.getDefaultValue() != null ? field.getDefaultValue() : "");
429	            rendered = rendered.replace(placeholder, value);
430	        }
431	        return rendered;
432	    }
433	
434	    private Map<String, String> parseFieldValues(String fieldValuesJson) {
435	        if (fieldValuesJson == null || fieldValuesJson.isBlank()) {
436	            return Map.of();
437	        }
438	        // Support simple JSON object: {"key":"value",...} or key=value,... format
439	        // Use a lightweight approach without pulling in Jackson explicitly
440	        java.util.Map<String, String> map = new java.util.LinkedHashMap<>();
441	        // Strip braces if JSON-like
442	        String cleaned = fieldValuesJson.trim();
443	        if (cleaned.startsWith("{")) {
444	            cleaned = cleaned.substring(1, cleaned.endsWith("}") ? cleaned.length() - 1 : cleaned.length());
445	        }
446	        for (String pair : cleaned.split(",")) {
447	            String[] kv = pair.split("[:=]", 2);
448	            if (kv.length == 2) {
449	                String key = kv[0].trim().replaceAll("^\"|\"$", "");
450	                String val = kv[1].trim().replaceAll("^\"|\"$", "");
451	                map.put(key, val);
452	            }
453	        }
454	        return map;
455	    }
456	
457	    private String sha256Hex(byte[] data) {
458	        try {
459	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
460	            byte[] hash = digest.digest(data);
461	            return HexFormat.of().formatHex(hash);
462	        } catch (NoSuchAlgorithmException e) {
463	            throw new RuntimeException("SHA-256 not available", e);
464	        }
465	    }
466	
467	    // =========================================================================
468	    // Inner utility: lightweight MultipartFile backed by a byte array
469	    // =========================================================================
470	
471	    /**
472	     * A minimal {@link MultipartFile} implementation backed by an in-memory byte array.
473	     * Used internally to wrap raw signature bytes before passing to StorageService.
474	     */
475	    private static final class ByteArrayMultipartFile implements MultipartFile {
476	
477	        private final String name;
478	        private final String originalFilename;
479	        private final String contentType;
480	        private final byte[] content;
481	
482	        ByteArrayMultipartFile(String name, String originalFilename,
483	                               String contentType, byte[] content) {
484	            this.name = name;
485	            this.originalFilename = originalFilename;
486	            this.contentType = contentType;
487	            this.content = content != null ? content : new byte[0];
488	        }
489	
490	        @Override public String getName()             { return name; }
491	        @Override public String getOriginalFilename() { return originalFilename; }
492	        @Override public String getContentType()      { return contentType; }
493	        @Override public boolean isEmpty()            { return content.length == 0; }
494	        @Override public long getSize()               { return content.length; }
495	        @Override public byte[] getBytes()            { return content; }
496	
497	        @Override
498	        public java.io.InputStream getInputStream() {
499	            return new java.io.ByteArrayInputStream(content);
500	        }
501	
502	        @Override
503	        public void transferTo(java.io.File dest) throws java.io.IOException {
504	            java.nio.file.Files.write(dest.toPath(), content);
505	        }
506	    }
507	}
