13	
14	@Service
15	@Transactional
16	public class SearchService {
17	
18	    private final SearchTrendRepository searchTrendRepository;
19	
20	    public SearchService(SearchTrendRepository searchTrendRepository) {
21	        this.searchTrendRepository = searchTrendRepository;
22	    }
23	
24	    @Transactional(readOnly = true)
25	    public List<String> getAutocompleteSuggestions(String partial) {
26	        return searchTrendRepository.findBySearchTermContainingIgnoreCase(partial)
27	                .stream()
28	                .map(SearchTrend::getSearchTerm)
29	                .limit(10)
30	                .collect(Collectors.toList());
31	    }
32	
33	    @Transactional(readOnly = true)
34	    public List<SearchTrend> getTrendingSearches() {
35	        return searchTrendRepository.findTop10ByOrderBySearchCountDesc();
36	    }
37	
38	    public void updateTrends(String searchTerm) {
39	        Optional<SearchTrend> existing = searchTrendRepository.findBySearchTerm(searchTerm);
40	        if (existing.isPresent()) {
41	            SearchTrend trend = existing.get();
42	            trend.setSearchCount(trend.getSearchCount() + 1);
43	            trend.setLastSearchedAt(LocalDateTime.now());
44	            searchTrendRepository.save(trend);
45	        } else {
46	            SearchTrend trend = new SearchTrend();
47	            trend.setSearchTerm(searchTerm);
48	            trend.setSearchCount(1);
49	            trend.setLastSearchedAt(LocalDateTime.now());
50	            trend.setPeriodStart(LocalDate.now());
51	            trend.setPeriodEnd(LocalDate.now());
52	            searchTrendRepository.save(trend);
