498	/* ── Password complexity hints ──────────────────────────────── */
499	function initPasswordHints(inputEl, hintsContainer) {
500	    if (!inputEl || !hintsContainer) return;
501	
502	    const rules = [
503	        { id: 'len',    label: 'At least 12 characters',       test: v => v.length >= 12 },
504	        { id: 'upper',  label: 'One uppercase letter',          test: v => /[A-Z]/.test(v) },
505	        { id: 'lower',  label: 'One lowercase letter',          test: v => /[a-z]/.test(v) },
506	        { id: 'digit',  label: 'One number',                    test: v => /\d/.test(v) },
507	        { id: 'special', label: 'One special character',        test: v => /[^A-Za-z0-9]/.test(v) }
508	    ];
509	
510	    // Build hint items
511	    hintsContainer.innerHTML = '';
512	    rules.forEach(r => {
513	        const div = document.createElement('div');
514	        div.className = 'pw-hint';
515	        div.id = 'hint-' + r.id;
516	        div.innerHTML = `<span class="pw-hint-icon">✗</span><span>${r.label}</span>`;
517	        hintsContainer.appendChild(div);
518	    });
519	
520	    inputEl.addEventListener('input', function () {
521	        const val = this.value;
522	        rules.forEach(r => {
523	            const el = hintsContainer.querySelector('#hint-' + r.id);
524	            if (!el) return;
525	            const ok = r.test(val);
526	            el.classList.toggle('valid', ok);
527	            el.querySelector('.pw-hint-icon').textContent = ok ? '✓' : '✗';
528	        });
529	    });
530	}
