533	function initCharCounter(textareaEl, counterEl, max) {
534	    if (!textareaEl || !counterEl) return;
535	
536	    function update() {
537	        const len = textareaEl.value.length;
538	        const remaining = max - len;
539	        counterEl.textContent = `${len} / ${max}`;
540	        counterEl.classList.toggle('near-limit', remaining <= max * 0.1 && remaining > 0);
541	        counterEl.classList.toggle('at-limit',   remaining <= 0);
542	    }
543	
544	    textareaEl.addEventListener('input', update);
545	    update();
546	}
