51	    /**
52	     * Creates a new (inactive) ranking strategy version.
53	     */
54	    public RankingStrategyVersion createRankingStrategy(String versionLabel,
55	                                                        BigDecimal creditScoreWeight,
56	                                                        BigDecimal positiveRateWeight,
57	                                                        BigDecimal reviewQualityWeight,
58	                                                        BigDecimal minCreditScoreThreshold,
59	                                                        BigDecimal minPositiveRateThreshold,
60	                                                        Long createdBy) {
61	        RankingStrategyVersion strategy = new RankingStrategyVersion();
62	        strategy.setVersionLabel(versionLabel);
