74	    /**
75	     * Deactivates all strategies, then activates the specified one.
76	     * Logs the activation in AdminAccessLog.
77	     */
78	    public RankingStrategyVersion activateStrategy(Long strategyId, Long adminUserId) {
79	        RankingStrategyVersion target = strategyRepository.findById(strategyId)
80	                .orElseThrow(() -> new EntityNotFoundException("RankingStrategyVersion", strategyId));
81	
82	        // Deactivate all existing active strategies
83	        List<RankingStrategyVersion> all = strategyRepository.findAllByOrderByCreatedAtDesc();
84	        for (RankingStrategyVersion s : all) {
85	            if (s.isActive()) {
86	                s.setActive(false);
87	                strategyRepository.save(s);
88	            }
89	        }
90	
91	        // Activate the target
92	        target.setActive(true);
93	        RankingStrategyVersion activated = strategyRepository.save(target);
94	
95	        // Log the action
96	        AdminAccessLog log = new AdminAccessLog();
97	        log.setAdminUserId(adminUserId);
98	        log.setActionType("STRATEGY_ACTIVATE");
99	        log.setTargetEntity("RankingStrategyVersion");
100	        log.setTargetId(strategyId);
101	        log.setReason("Strategy activation");
102	        log.setCreatedAt(LocalDateTime.now());
103	        accessLogRepository.save(log);
104	
105	        return activated;
