125	    /**
126	     * Returns search analytics:
127	     * - totalSearches (count)
128	     * - totalClicks (count)
129	     * - uniqueKeywords (distinct search terms count)
130	     * - topTerms (top 10 trends by search count)
131	     * - topClickedItems (top 10 items by click count)
132	     * - recentSearches (last 20 search log entries)
133	     */
134	    @Transactional(readOnly = true)
135	    public Map<String, Object> getSearchAnalytics() {
136	        long totalSearches = searchLogRepository.count();
137	
138	        List<SearchClickLog> allClicks = searchClickLogRepository.findAll();
139	        long totalClicks = allClicks.size();
140	
141	        // Count distinct non-null search terms from trends table
142	        long uniqueKeywords = searchTrendRepository.count();
143	
144	        List<SearchTrend> topTerms = searchTrendRepository.findTop10ByOrderBySearchCountDesc();
145	
146	        // Compute top clicked items by grouping click logs
147	        Map<Long, Long> clicksPerItem = allClicks.stream()
148	                .filter(c -> c.getItemId() != null)
149	                .collect(Collectors.groupingBy(SearchClickLog::getItemId, Collectors.counting()));
150	        List<ClickedItemSummary> topClickedItems = clicksPerItem.entrySet().stream()
151	                .sorted(Map.Entry.<Long, Long>comparingByValue(Comparator.reverseOrder()))
152	                .limit(10)
153	                .map(e -> new ClickedItemSummary(e.getKey(), null, e.getValue()))
154	                .collect(Collectors.toList());
155	
156	        List<SearchLog> recentSearches = searchLogRepository.findAll().stream()
157	                .sorted((a, b) -> {
158	                    if (a.getSearchedAt() == null && b.getSearchedAt() == null) return 0;
159	                    if (a.getSearchedAt() == null) return 1;
160	                    if (b.getSearchedAt() == null) return -1;
161	                    return b.getSearchedAt().compareTo(a.getSearchedAt());
162	                })
163	                .limit(20)
164	                .toList();
