176	    /**
177	     * Returns all admin access logs ordered by createdAt descending.
178	     */
179	    @Transactional(readOnly = true)
180	    public List<AdminAccessLog> getAccessLogs() {
181	        return accessLogRepository.findAll().stream()
182	                .sorted((a, b) -> {
183	                    if (a.getCreatedAt() == null && b.getCreatedAt() == null) return 0;
184	                    if (a.getCreatedAt() == null) return 1;
185	                    if (b.getCreatedAt() == null) return -1;
186	                    return b.getCreatedAt().compareTo(a.getCreatedAt());
187	                })
188	                .toList();
189	    }
