1	package com.reclaim.portal.storage.service;
2	
3	import com.reclaim.portal.common.config.ReclaimProperties;
4	import com.reclaim.portal.common.exception.BusinessRuleException;
5	import com.reclaim.portal.common.exception.EntityNotFoundException;
6	import com.reclaim.portal.storage.dto.StorageResult;
7	import org.springframework.stereotype.Service;
8	import org.springframework.web.multipart.MultipartFile;
9	
10	import java.io.IOException;
11	import java.io.InputStream;
12	import java.nio.file.Files;
13	import java.nio.file.Path;
14	import java.nio.file.Paths;
15	import java.nio.file.StandardCopyOption;
16	import java.security.DigestInputStream;
17	import java.security.MessageDigest;
18	import java.security.NoSuchAlgorithmException;
19	import java.util.HexFormat;
20	import java.util.List;
21	import java.util.UUID;
22	
23	@Service
24	public class StorageService {
25	
26	    private static final java.util.Map<String, String> EXTENSION_CONTENT_TYPE_MAP =
27	            java.util.Map.of(
28	                    "jpg", "image/jpeg",
29	                    "jpeg", "image/jpeg",
30	                    "png", "image/png"
31	            );
32	
33	    private final ReclaimProperties reclaimProperties;
34	
35	    public StorageService(ReclaimProperties reclaimProperties) {
36	        this.reclaimProperties = reclaimProperties;
37	    }
38	
39	    /**
40	     * Validates and stores the given multipart file under a subdirectory of the configured storage root.
41	     *
42	     * @param file     the file to store
43	     * @param subDirectory subdirectory within the storage root (e.g. "signatures", "evidence")
44	     * @return a StorageResult record describing the stored file
45	     */
46	    public StorageResult store(MultipartFile file, String subDirectory) {
47	        ReclaimProperties.Storage storageConfig = reclaimProperties.getStorage();
48	
49	        if (file == null || file.isEmpty()) {
50	            throw new BusinessRuleException("File must not be empty");
51	        }
52	
53	        if (file.getSize() > storageConfig.getMaxFileSize()) {
54	            throw new BusinessRuleException("File size exceeds the maximum allowed size of "
55	                    + storageConfig.getMaxFileSize() + " bytes");
56	        }
57	
58	        String originalFilename = file.getOriginalFilename() != null
59	                ? file.getOriginalFilename()
60	                : "unknown";
61	
62	        String extension = extractExtension(originalFilename).toLowerCase();
63	        List<String> allowedExtensions = storageConfig.getAllowedExtensionList();
64	        if (!allowedExtensions.contains(extension)) {
65	            throw new BusinessRuleException("File extension '" + extension
66	                    + "' is not allowed. Allowed extensions: " + allowedExtensions);
67	        }
68	
69	        String expectedContentType = EXTENSION_CONTENT_TYPE_MAP.get(extension);
70	        String actualContentType = file.getContentType();
71	        if (expectedContentType != null && !expectedContentType.equalsIgnoreCase(actualContentType)) {
72	            throw new BusinessRuleException("Content type '" + actualContentType
73	                    + "' does not match expected type '" + expectedContentType
74	                    + "' for extension '" + extension + "'");
75	        }
76	
77	        String rootPath = storageConfig.getRootPath();
78	        Path targetDir = Paths.get(rootPath, subDirectory);
79	        try {
80	            Files.createDirectories(targetDir);
81	
82	            String storedFileName = UUID.randomUUID() + "." + extension;
83	            Path destination = targetDir.resolve(storedFileName);
84	
85	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
86	            try (InputStream is = new DigestInputStream(file.getInputStream(), digest)) {
87	                Files.copy(is, destination, StandardCopyOption.REPLACE_EXISTING);
88	            }
89	
90	            String checksum = HexFormat.of().formatHex(digest.digest());
91	            String relativeFilePath = subDirectory + "/" + storedFileName;
92	
93	            return new StorageResult(
94	                    relativeFilePath,
95	                    checksum,
96	                    originalFilename,
97	                    file.getContentType(),
98	                    file.getSize()
99	            );
100	        } catch (IOException | NoSuchAlgorithmException e) {
101	            throw new RuntimeException("Failed to store file: " + e.getMessage(), e);
102	        }
103	    }
104	
105	    /**
106	     * Retrieves the raw bytes for a stored file.
107	     *
108	     * @param filePath the relative file path as returned by store()
109	     * @return byte array of file contents
110	     */
111	    public byte[] retrieve(String filePath) {
112	        Path resolvedPath = resolveAndValidatePath(filePath);
113	        if (!Files.exists(resolvedPath)) {
114	            throw new EntityNotFoundException("File not found: " + filePath);
115	        }
116	        try {
117	            return Files.readAllBytes(resolvedPath);
118	        } catch (IOException e) {
119	            throw new RuntimeException("Failed to read file: " + filePath, e);
120	        }
121	    }
122	
123	    /**
124	     * Verifies that the stored file matches the expected SHA-256 checksum.
125	     *
126	     * @param filePath         the relative file path
127	     * @param expectedChecksum the hex-encoded SHA-256 checksum to verify against
128	     * @return true if checksum matches, false otherwise
129	     */
130	    public boolean verifyChecksum(String filePath, String expectedChecksum) {
131	        Path resolvedPath = resolveAndValidatePath(filePath);
132	        if (!Files.exists(resolvedPath)) {
133	            throw new EntityNotFoundException("File not found: " + filePath);
134	        }
135	        try {
136	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
137	            try (InputStream is = new DigestInputStream(Files.newInputStream(resolvedPath), digest)) {
138	                byte[] buffer = new byte[8192];
139	                while (is.read(buffer) != -1) {
140	                    // digest is updated by DigestInputStream
141	                }
142	            }
143	            String actualChecksum = HexFormat.of().formatHex(digest.digest());
144	            return actualChecksum.equalsIgnoreCase(expectedChecksum);
145	        } catch (IOException | NoSuchAlgorithmException e) {
146	            throw new RuntimeException("Failed to verify checksum for file: " + filePath, e);
147	        }
148	    }
149	
150	    /**
151	     * Deletes a stored file.
152	     *
153	     * @param filePath the relative file path as returned by store()
154	     */
155	    public void delete(String filePath) {
156	        Path resolvedPath = resolveAndValidatePath(filePath);
157	        if (!Files.exists(resolvedPath)) {
158	            throw new EntityNotFoundException("File not found: " + filePath);
159	        }
160	        try {
161	            Files.delete(resolvedPath);
162	        } catch (IOException e) {
163	            throw new RuntimeException("Failed to delete file: " + filePath, e);
164	        }
165	    }
166	
167	    // -------------------------------------------------------------------------
168	    // Helpers
169	    // -------------------------------------------------------------------------
170	
171	    private Path resolveAndValidatePath(String filePath) {
172	        if (filePath == null || filePath.contains("..")) {
173	            throw new BusinessRuleException("Invalid file path: path traversal is not allowed");
174	        }
175	
176	        String rootPath = reclaimProperties.getStorage().getRootPath();
177	        Path rootNormalized = Paths.get(rootPath).toAbsolutePath().normalize();
178	        Path resolved = rootNormalized.resolve(filePath).normalize();
179	
180	        if (!resolved.startsWith(rootNormalized)) {
181	            throw new BusinessRuleException("Invalid file path: access outside storage root is not allowed");
182	        }
183	
184	        return resolved;
185	    }
186	
187	    private String extractExtension(String filename) {
188	        int lastDot = filename.lastIndexOf('.');
189	        if (lastDot < 0 || lastDot == filename.length() - 1) {
190	            return "";
191	        }
192	        return filename.substring(lastDot + 1);
193	    }
194	}
