58	    public List<RecyclingItem> searchItems(String keyword, String category, String condition,
59	                                           BigDecimal minPrice, BigDecimal maxPrice, Long userId) {
60	        List<RecyclingItem> results;
61	        try {
62	            results = recyclingItemRepository.searchItemsFullText(keyword, category, condition, minPrice, maxPrice);
63	        } catch (Exception e) {
64	            // Fallback to LIKE search (H2 or when full-text index not available)
65	            results = recyclingItemRepository.searchItems(keyword, category, condition, minPrice, maxPrice);
66	        }
67	
68	        if (keyword != null && !keyword.isBlank()) {
69	            searchService.updateTrends(keyword);
70	        }
71	
72	        List<RecyclingItem> rankedResults = rankingService.rankItems(results, userId);
73	
74	        SearchLog searchLog = new SearchLog();
75	        searchLog.setUserId(userId);
76	        searchLog.setSearchTerm(keyword);
77	        searchLog.setCategoryFilter(category);
78	        searchLog.setConditionFilter(condition);
79	        searchLog.setMinPrice(minPrice);
80	        searchLog.setMaxPrice(maxPrice);
81	        searchLog.setResultCount(rankedResults.size());
82	        searchLog.setSearchedAt(LocalDateTime.now());
83	        searchLog = searchLogRepository.save(searchLog);
84	        lastSearchLogId = searchLog.getId();
85	
86	        return rankedResults;
