112	    public String checkDuplicate(String title, String attributes) {
113	        String normalizedTitle = title == null ? "" : title.toLowerCase().trim().replaceAll("\\s+", " ");
114	        String combined = normalizedTitle + (attributes == null ? "" : attributes);
115	        String hash = sha256(combined);
116	
117	        if (itemFingerprintRepository.findByFingerprintHash(hash).isPresent()) {
118	            return "EXACT_DUPLICATE";
119	        }
120	
121	        List<RecyclingItem> sameTitle = recyclingItemRepository.findByNormalizedTitle(normalizedTitle);
122	        if (!sameTitle.isEmpty()) {
123	            return "NEAR_DUPLICATE";
124	        }
125	
126	        return "UNIQUE";
127	    }
128	
129	    private String sha256(String input) {
130	        try {
131	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
132	            byte[] hash = digest.digest(input.getBytes(StandardCharsets.UTF_8));
133	            return HexFormat.of().formatHex(hash);
134	        } catch (NoSuchAlgorithmException e) {
135	            throw new IllegalStateException("SHA-256 not available", e);
136	        }
137	    }
138	}
