290	/* ── Canvas signature pad ────────────────────────────────────── */
291	function initSignaturePad(canvasEl, clearBtnEl, placeholder) {
292	    if (!canvasEl) return null;
293	
294	    const ctx = canvasEl.getContext('2d');
295	    let drawing = false;
296	    let hasStrokes = false;
297	
298	    // Match canvas logical size to its CSS display size
299	    function resize() {
300	        const rect = canvasEl.getBoundingClientRect();
301	        // Preserve existing drawing
302	        const imgData = ctx.getImageData(0, 0, canvasEl.width, canvasEl.height);
303	        canvasEl.width  = rect.width  || 600;
304	        canvasEl.height = rect.height || 240;
305	        ctx.putImageData(imgData, 0, 0);
306	        ctx.strokeStyle = '#111';
307	        ctx.lineWidth   = 2;
308	        ctx.lineCap     = 'round';
309	        ctx.lineJoin    = 'round';
310	    }
311	
312	    resize();
313	
314	    function getPos(e) {
315	        const rect = canvasEl.getBoundingClientRect();
316	        const src  = e.touches ? e.touches[0] : e;
317	        return {
318	            x: (src.clientX - rect.left) * (canvasEl.width  / rect.width),
319	            y: (src.clientY - rect.top)  * (canvasEl.height / rect.height)
320	        };
321	    }
322	
323	    function startDraw(e) {
324	        e.preventDefault();
325	        drawing = true;
326	        const p = getPos(e);
327	        ctx.beginPath();
328	        ctx.moveTo(p.x, p.y);
329	    }
330	
331	    function draw(e) {
332	        if (!drawing) return;
333	        e.preventDefault();
334	        const p = getPos(e);
335	        ctx.lineTo(p.x, p.y);
336	        ctx.stroke();
337	        hasStrokes = true;
338	        if (placeholder) placeholder.classList.add('hidden');
339	    }
340	
341	    function endDraw() { drawing = false; }
342	
343	    // Mouse events
344	    canvasEl.addEventListener('mousedown',  startDraw);
345	    canvasEl.addEventListener('mousemove',  draw);
346	    canvasEl.addEventListener('mouseup',    endDraw);
347	    canvasEl.addEventListener('mouseleave', endDraw);
348	
349	    // Touch events
350	    canvasEl.addEventListener('touchstart', startDraw, { passive: false });
351	    canvasEl.addEventListener('touchmove',  draw,      { passive: false });
352	    canvasEl.addEventListener('touchend',   endDraw);
353	
354	    // Clear button
355	    if (clearBtnEl) {
356	        clearBtnEl.addEventListener('click', function () {
357	            ctx.clearRect(0, 0, canvasEl.width, canvasEl.height);
358	            hasStrokes = false;
359	            if (placeholder) placeholder.classList.remove('hidden');
360	        });
361	    }
362	
363	    window.addEventListener('resize', debounce(resize, 200));
364	
365	    return {
366	        isEmpty:  () => !hasStrokes,
367	        toPNG:    () => canvasEl.toDataURL('image/png'),
368	        toBlob:   (cb) => canvasEl.toBlob(cb, 'image/png'),
369	        clear:    () => clearBtnEl && clearBtnEl.click()
370	    };
371	}
