548	/* ── Toggle password visibility ─────────────────────────────── */
549	function initTogglePassword(toggleBtn, inputEl) {
550	    if (!toggleBtn || !inputEl) return;
551	    toggleBtn.addEventListener('click', function () {
552	        if (inputEl.type === 'password') {
553	            inputEl.type = 'text';
554	            this.setAttribute('aria-label', 'Hide password');
555	        } else {
556	            inputEl.type = 'password';
557	            this.setAttribute('aria-label', 'Show password');
558	        }
559	    });
560	}
