1	package com.reclaim.portal.users.controller;
2	
3	import com.reclaim.portal.auth.entity.User;
4	import com.reclaim.portal.auth.repository.UserRepository;
5	import com.reclaim.portal.common.exception.EntityNotFoundException;
6	import com.reclaim.portal.users.dto.MaskedUserProfileDto;
7	import com.reclaim.portal.users.dto.UserProfileDto;
8	import com.reclaim.portal.users.service.UserService;
9	import org.springframework.http.ResponseEntity;
10	import org.springframework.security.access.prepost.PreAuthorize;
11	import org.springframework.security.core.Authentication;
12	import org.springframework.security.core.userdetails.UserDetails;
13	import org.springframework.web.bind.annotation.*;
14	
15	@RestController
16	@RequestMapping("/api/users")
17	public class UserApiController {
18	
19	    private final UserService userService;
20	    private final UserRepository userRepository;
21	
22	    public UserApiController(UserService userService, UserRepository userRepository) {
23	        this.userService = userService;
24	        this.userRepository = userRepository;
25	    }
26	
27	    /**
28	     * GET /api/users/{id}/profile
29	     * Admins and the user themselves receive the full profile.
30	     * Reviewers receive a masked profile.
31	     */
32	    @GetMapping("/{id}/profile")
33	    public ResponseEntity<?> getProfile(@PathVariable Long id, Authentication authentication) {
34	        boolean isAdmin = hasRole(authentication, "ROLE_ADMIN");
35	        boolean isReviewer = hasRole(authentication, "ROLE_REVIEWER");
36	        Long requestingUserId = resolveUserId(authentication);
37	        boolean isSelf = requestingUserId != null && requestingUserId.equals(id);
38	
39	        if (isSelf) {
40	            UserProfileDto dto = userService.getUserProfile(id);
41	            return ResponseEntity.ok(dto);
42	        } else if (isAdmin || isReviewer) {
43	            // Admins and reviewers see masked profiles by default.
44	            // Full PII requires the explicit POST /reveal endpoint with audit logging.
45	            MaskedUserProfileDto dto = userService.getMaskedUserProfile(id);
46	            return ResponseEntity.ok(dto);
47	        } else {
48	            throw new com.reclaim.portal.common.exception.BusinessRuleException("Access denied to user profile");
49	        }
50	    }
51	
52	    /**
53	     * POST /api/users/{id}/reveal
54	     * Admin only – reveals full PII and logs the access.
55	     * The endpoint is also accessible via /api/admin/users/{id}/reveal from AdminApiController.
56	     */
57	    @PostMapping("/{id}/reveal")
58	    @PreAuthorize("hasRole('ADMIN')")
59	    public ResponseEntity<UserProfileDto> revealPii(@PathVariable Long id,
60	                                                    @RequestParam String reason,
61	                                                    Authentication authentication) {
62	        Long adminUserId = resolveUserId(authentication);
63	        UserProfileDto dto = userService.revealPii(adminUserId, id, reason);
64	        return ResponseEntity.ok(dto);
65	    }
66	
67	    // -------------------------------------------------------------------------
68	    // Helpers
69	    // -------------------------------------------------------------------------
70	
71	    private boolean hasRole(Authentication auth, String role) {
72	        if (auth == null) return false;
73	        return auth.getAuthorities().stream()
74	                .anyMatch(a -> a.getAuthority().equals(role));
75	    }
76	
77	    private Long resolveUserId(Authentication auth) {
78	        if (auth == null) return null;
79	        String username = ((UserDetails) auth.getPrincipal()).getUsername();
80	        return userRepository.findByUsername(username)
81	                .map(User::getId)
82	                .orElseThrow(() -> new EntityNotFoundException("User not found: " + username));
83	    }
84	}
