18	@ControllerAdvice
19	public class GlobalExceptionHandler {
20	
21	    @ExceptionHandler(MethodArgumentNotValidException.class)
22	    public ResponseEntity<Map<String, Object>> handleValidation(MethodArgumentNotValidException ex) {
23	        List<String> errors = ex.getBindingResult().getFieldErrors().stream()
24	            .map(FieldError::getDefaultMessage)
25	            .collect(Collectors.toList());
26	
27	        Map<String, Object> body = buildBody(
28	            HttpStatus.BAD_REQUEST.value(),
29	            "Validation failed",
30	            "Bad Request"
31	        );
32	        body.put("errors", errors);
33	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
34	    }
35	
36	    @ExceptionHandler(AccessDeniedException.class)
37	    public ResponseEntity<Map<String, Object>> handleAccessDenied(AccessDeniedException ex) {
38	        return ResponseEntity.status(HttpStatus.FORBIDDEN)
39	            .body(buildBody(HttpStatus.FORBIDDEN.value(), ex.getMessage(), "Forbidden"));
40	    }
41	
42	    @ExceptionHandler(EntityNotFoundException.class)
43	    public ResponseEntity<Map<String, Object>> handleEntityNotFound(EntityNotFoundException ex) {
44	        return ResponseEntity.status(HttpStatus.NOT_FOUND)
45	            .body(buildBody(HttpStatus.NOT_FOUND.value(), ex.getMessage(), "Not Found"));
46	    }
47	
48	    @ExceptionHandler(BusinessRuleException.class)
49	    public ResponseEntity<Map<String, Object>> handleBusinessRule(BusinessRuleException ex) {
50	        return ResponseEntity.status(HttpStatus.CONFLICT)
51	            .body(buildBody(HttpStatus.CONFLICT.value(), ex.getMessage(), "Conflict"));
52	    }
53	
54	    @ExceptionHandler(MaxUploadSizeExceededException.class)
55	    public ResponseEntity<Map<String, Object>> handleMaxUploadSize(MaxUploadSizeExceededException ex) {
56	        return ResponseEntity.status(HttpStatus.PAYLOAD_TOO_LARGE)
57	            .body(buildBody(HttpStatus.PAYLOAD_TOO_LARGE.value(), ex.getMessage(), "Payload Too Large"));
58	    }
59	
60	    @ExceptionHandler(Exception.class)
61	    public ResponseEntity<Map<String, Object>> handleGeneral(Exception ex) {
62	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
63	            .body(buildBody(HttpStatus.INTERNAL_SERVER_ERROR.value(), ex.getMessage(), "Internal Server Error"));
64	    }
65	
66	    private Map<String, Object> buildBody(int status, String message, String error) {
67	        Map<String, Object> body = new HashMap<>();
68	        body.put("timestamp", Instant.now().toString());
69	        body.put("status", status);
70	        body.put("error", error);
71	        body.put("message", message);
72	        return body;
73	    }
74	}
