64	                : "unknown";
65	
66	        String extension = extractExtension(originalFilename).toLowerCase();
67	        List<String> allowedExtensions = storageConfig.getAllowedExtensionList();
68	        if (!allowedExtensions.contains(extension)) {
69	            throw new BusinessRuleException("File extension '" + extension
70	                    + "' is not allowed. Allowed extensions: " + allowedExtensions);
71	        }
72	
73	        String expectedContentType = EXTENSION_CONTENT_TYPE_MAP.get(extension);
74	        String actualContentType = file.getContentType();
75	        if (expectedContentType != null && !expectedContentType.equalsIgnoreCase(actualContentType)) {
76	            throw new BusinessRuleException("Content type '" + actualContentType
77	                    + "' does not match expected type '" + expectedContentType
78	                    + "' for extension '" + extension + "'");
79	        }
80	
81	        String rootPath = storageConfig.getRootPath();
82	        Path targetDir = Paths.get(rootPath, subDirectory);
83	        try {
84	            Files.createDirectories(targetDir);
85	
86	            String storedFileName = UUID.randomUUID() + "." + extension;
87	            Path destination = targetDir.resolve(storedFileName);
88	
89	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
90	            try (InputStream is = new DigestInputStream(file.getInputStream(), digest)) {
91	                Files.copy(is, destination, StandardCopyOption.REPLACE_EXISTING);
92	            }
93	
94	            String checksum = HexFormat.of().formatHex(digest.digest());
95	            String relativeFilePath = subDirectory + "/" + storedFileName;
96	
97	            return new StorageResult(
98	                    relativeFilePath,
99	                    checksum,
100	                    originalFilename,
101	                    file.getContentType(),
102	                    file.getSize()
103	            );
104	        } catch (IOException | NoSuchAlgorithmException e) {
105	            log.error("Failed to store file in {}: {}", subDirectory, e.getMessage());
106	            throw new RuntimeException("Failed to store file: " + e.getMessage(), e);
107	        }
108	    }
109	
110	    /**
111	     * Retrieves the raw bytes for a stored file.
112	     *
113	     * @param filePath the relative file path as returned by store()
114	     * @return byte array of file contents
115	     */
116	    public byte[] retrieve(String filePath) {
117	        Path resolvedPath = resolveAndValidatePath(filePath);
118	        if (!Files.exists(resolvedPath)) {
119	            throw new EntityNotFoundException("File not found: " + filePath);
120	        }
121	        try {
122	            return Files.readAllBytes(resolvedPath);
123	        } catch (IOException e) {
124	            throw new RuntimeException("Failed to read file: " + filePath, e);
125	        }
126	    }
127	
128	    /**
129	     * Verifies that the stored file matches the expected SHA-256 checksum.
130	     *
131	     * @param filePath         the relative file path
132	     * @param expectedChecksum the hex-encoded SHA-256 checksum to verify against
133	     * @return true if checksum matches, false otherwise
134	     */
135	    public boolean verifyChecksum(String filePath, String expectedChecksum) {
136	        Path resolvedPath = resolveAndValidatePath(filePath);
137	        if (!Files.exists(resolvedPath)) {
138	            throw new EntityNotFoundException("File not found: " + filePath);
139	        }
140	        try {
141	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
142	            try (InputStream is = new DigestInputStream(Files.newInputStream(resolvedPath), digest)) {
143	                byte[] buffer = new byte[8192];
144	                while (is.read(buffer) != -1) {
145	                    // digest is updated by DigestInputStream
146	                }
147	            }
148	            String actualChecksum = HexFormat.of().formatHex(digest.digest());
149	            return actualChecksum.equalsIgnoreCase(expectedChecksum);
150	        } catch (IOException | NoSuchAlgorithmException e) {
151	            throw new RuntimeException("Failed to verify checksum for file: " + filePath, e);
152	        }
153	    }
154	
155	    /**
156	     * Deletes a stored file.
157	     *
158	     * @param filePath the relative file path as returned by store()
159	     */
160	    public void delete(String filePath) {
161	        Path resolvedPath = resolveAndValidatePath(filePath);
162	        if (!Files.exists(resolvedPath)) {
163	            throw new EntityNotFoundException("File not found: " + filePath);
164	        }
165	        try {
166	            Files.delete(resolvedPath);
167	        } catch (IOException e) {
168	            throw new RuntimeException("Failed to delete file: " + filePath, e);
169	        }
170	    }
171	
172	    // -------------------------------------------------------------------------
173	    // Helpers
174	    // -------------------------------------------------------------------------
175	
176	    private Path resolveAndValidatePath(String filePath) {
177	        if (filePath == null || filePath.contains("..")) {
178	            log.warn("Path traversal attempt blocked: {}", filePath);
179	            throw new BusinessRuleException("Invalid file path: path traversal is not allowed");
180	        }
181	
182	        String rootPath = reclaimProperties.getStorage().getRootPath();
183	        Path rootNormalized = Paths.get(rootPath).toAbsolutePath().normalize();
184	        Path resolved = rootNormalized.resolve(filePath).normalize();
185	
186	        if (!resolved.startsWith(rootNormalized)) {
187	            throw new BusinessRuleException("Invalid file path: access outside storage root is not allowed");
188	        }
189	
190	        return resolved;
191	    }
192	
193	    private String extractExtension(String filename) {
194	        int lastDot = filename.lastIndexOf('.');
195	        if (lastDot < 0 || lastDot == filename.length() - 1) {
196	            return "";
197	        }
198	        return filename.substring(lastDot + 1);
199	    }
200	}
