        mockMvc.perform(get("/storage/" + storedFilePath))
               .andExpect(status().isOk())
               .andExpect(content().contentType(MediaType.IMAGE_PNG))
               .andExpect(header().exists("Content-Length"))
               .andExpect(header().exists("Cache-Control"));
    }

